reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}


resource "aws_route53_zone" "primary" {
  name = "example53.com"
}

resource "aws_cloudwatch_log_group" "aws_route53_example_com" {
  name              = "/aws/route53/${aws_route53_zone.primary.name}"
  retention_in_days = 30
}

# Example CloudWatch log resource policy to allow Route53 to write logs
# to any log group under /aws/route53/*

data "aws_iam_policy_document" "route53-query-logging-policy" {
  statement {
    actions = [
      "logs:CreateLogStream",
      "logs:PutLogEvents",
    ]

    resources = ["arn:aws:logs:*:*:log-group:/aws/route53/*"]

    principals {
      identifiers = ["route53.amazonaws.com"]
      type        = "Service"
    }
  }
}

resource "aws_cloudwatch_log_resource_policy" "route53-query-logging-policy" {
  policy_document = data.aws_iam_policy_document.route53-query-logging-policy.json
  policy_name     = "route53-query-logging-policy"
}

resource "aws_route53_query_log" "example_com" {
  depends_on = [aws_cloudwatch_log_resource_policy.route53-query-logging-policy]

  cloudwatch_log_group_arn = aws_cloudwatch_log_group.aws_route53_example_com.arn
  zone_id                  = aws_route53_zone.primary.zone_id
}

response:
To fulfill the request, we need to configure several components within AWS using Terraform:

1. **Create an AWS Route 53 Hosted Zone** with the name "primary".
2. **Create an AWS CloudWatch Log Group** with the name "aws_route53_example_com" for storing the query logs.
3. **Create an AWS CloudWatch Log Resource Policy** with the name "route53-query-logging-policy" to define access permissions for the CloudWatch Logs.
4. **Create an AWS Route 53 CloudWatch Query Logging Config** that points to the created CloudWatch Log Group for logging query events from the Hosted Zone.

Let's implement these steps:

```hcl
provider "aws" {
  region = "us-east-1" # Specify your desired AWS region
}

resource "aws_route53_zone" "primary" {
  name = "example.com"
}

resource "aws_cloudwatch_log_group" "route53_log_group" {
  name = "/aws/route53/example.com"
}

resource "aws_iam_policy" "route53_query_logging_policy" {
  name   = "route53-query-logging-policy"
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect    = "Allow"
        Action    = [
          "logs:CreateLogStream",
          "logs:PutLogEvents",
          "logs:DescribeLogStreams"
        ]
        Resource = "arn:aws:logs:*:*:log-group:/aws/route53/example.com"
      }
    ]
  })
}

resource "aws_route53_query_logging_config" "primary" {
  cloudwatch_logs_log_group_arn = aws_cloudwatch_log_group.route53_log_group.arn
  cloudwatch_logs_role_arn      = aws_iam_policy.route53_query_logging_policy.arn
  zone_id                       = aws_route53_zone.primary.zone_id
}
```

### Explanation of the Code:

- **Provider**: Specifies AWS as the cloud provider, with the region set to "us-east-1". Adjust this as necessary.
- **aws_route53_zone**: Creates a Route 53 Hosted Zone named "example.com".
- **aws_cloudwatch_log_group**: Sets up a Log Group named "/aws/route53/example.com" for storing query logs.
- **aws_iam_policy**: Defines an IAM policy named "route53-query-logging-policy" with permissions to create log streams, put log events, and describe log streams in the specified CloudWatch Log Group.
- **aws_route53_query_logging_config**: Configures query logging for the "example.com" hosted zone by specifying the Log Group ARN, IAM policy ARN, and the ID of the hosted zone. This resource ties together the hosted zone and logging configurations. 

Make sure the IAM role associated with this configuration has the necessary permissions for access to both Route 53 and CloudWatch Logs. Adjust policies or roles as needed based on your environment constraints or security policies.

