reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
      configuration_aliases = [ aws.main, aws.us_east, aws.eu_central, aws.ap_southeast ]
    }
  }

  required_version = "~> 1.9.8"
}


provider "aws" {
  alias = "main"
  region = "us-west-2" 

  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

provider "aws" {
  alias  = "us_east"
  region = "us-east-1" # Example region for US East

  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

provider "aws" {
  alias  = "eu_central"
  region = "eu-central-1" # Example region for EU Central

  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

provider "aws" {
  alias  = "ap_southeast"
  region = "ap-southeast-1" # Example region for AP Southeast

  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_db_instance" "primary" {
  provider = aws.main
  identifier = "master"
  allocated_storage    = 20
  engine               = "postgres"
  instance_class       = "db.t3.micro"
  username             = "dbadmin"
  password             = "your_password_here"
  skip_final_snapshot  = true
  backup_retention_period  = 7
}

resource "aws_db_instance" "replica_us_east" {
  provider             = aws.us_east
  replicate_source_db  = aws_db_instance.primary.arn
  instance_class       = "db.t3.micro"
  identifier           = "mydb-replica-us-east"
  skip_final_snapshot  = true
}

resource "aws_db_instance" "replica_eu_central" {
  provider             = aws.eu_central
  replicate_source_db  = aws_db_instance.primary.arn
  instance_class       = "db.t3.micro"
  identifier           = "mydb-replica-eu-central"
  skip_final_snapshot  = true
}

resource "aws_db_instance" "replica_ap_southeast" {
  provider             = aws.ap_southeast
  replicate_source_db  = aws_db_instance.primary.arn

  instance_class       = "db.t3.micro"
  identifier           = "mydb-replica-ap-southeast"
  skip_final_snapshot  = true
}

# Route53 Hosted Zone
resource "aws_route53_zone" "main" {
  provider = aws.main
  name = "example53.com"
}


# Route53 Records for each RDS Read Replica with a Weighted Routing Policy
resource "aws_route53_record" "replica_us_east_cname" {
  provider = aws.main

  zone_id = aws_route53_zone.main.zone_id
  name    = "us.east.example53.com"
  type    = "CNAME"
  records = [aws_db_instance.replica_us_east.endpoint]
  ttl     = "60"
  weighted_routing_policy {
    weight = 30
  }
  set_identifier = "replica-us-east"
}

resource "aws_route53_record" "replica_eu_central_cname" {
  provider = aws.main

  zone_id = aws_route53_zone.main.zone_id
  name    = "eu.central.example53.com"
  type    = "CNAME"
  records = [aws_db_instance.replica_eu_central.endpoint]
  ttl     = "60"
  weighted_routing_policy {
    weight = 30
  }
  set_identifier = "replica-eu-central"
}

resource "aws_route53_record" "replica_ap_southeast_cname" {
  provider = aws.main

  zone_id = aws_route53_zone.main.zone_id
  name    = "ap.southeast.example53.com"
  type    = "CNAME"
  records = [aws_db_instance.replica_ap_southeast.endpoint]
  ttl     = "60"
  weighted_routing_policy {
    weight = 30
  }
  set_identifier = "replica-ap-southeast"
}

response:
To achieve the requirement of creating a weighted routing policy using AWS Route 53 for splitting the load between a primary database instance and three replicas, we'll need to break down and set the following steps:

1. Set up AWS provider configurations for each of the required regions using provider aliases.
2. Provision an RDS instance in the `us-west-1` region called `primary`.
3. Provision three more RDS database instances in `us-east-1`, `eu-central-1`, and `ap-southeast-1` respectively, named `replica_us_east`, `replica_eu_central`, and `replica_ap_southeast`.
4. Set up a Route 53 hosted zone and associated records for weighted routing.

Below is the Terraform HCL configuration encapsulating all these steps:

```hcl
provider "aws" {
  alias  = "main"
  region = "us-west-1"
}

provider "aws" {
  alias  = "us-east"
  region = "us-east-1"
}

provider "aws" {
  alias  = "eu-central"
  region = "eu-central-1"
}

provider "aws" {
  alias  = "ap-southeast"
  region = "ap-southeast-1"
}

resource "aws_rds_cluster" "primary" {
  provider     = aws.main
  cluster_identifier = "primary"
  engine       = "aurora"
  database_name = "mydb"
  master_username = "dbadmin"
  master_password = "SuperSecretPassword"
  db_subnet_group_name = "my-dbsubnet-group"
}

resource "aws_rds_cluster_instance" "replica_us_east" {
  provider             = aws.us-east
  identifier           = "replica-us-east"
  cluster_identifier   = aws_rds_cluster.primary.id
  engine               = aws_rds_cluster.primary.engine
  instance_class       = "db.r5.large"
  db_subnet_group_name = "my-dbsubnet-group-us-east"
}

resource "aws_rds_cluster_instance" "replica_eu_central" {
  provider             = aws.eu-central
  identifier           = "replica-eu-central"
  cluster_identifier   = aws_rds_cluster.primary.id
  engine               = aws_rds_cluster.primary.engine
  instance_class       = "db.r5.large"
  db_subnet_group_name = "my-dbsubnet-group-eu-central"
}

resource "aws_rds_cluster_instance" "replica_ap_southeast" {
  provider             = aws.ap-southeast
  identifier           = "replica-ap-southeast"
  cluster_identifier   = aws_rds_cluster.primary.id
  engine               = aws_rds_cluster.primary.engine
  instance_class       = "db.r5.large"
  db_subnet_group_name = "my-dbsubnet-group-ap-southeast"
}

resource "aws_route53_zone" "main" {
  provider = aws.main
  name     = "mydomain.com"
}

resource "aws_route53_record" "primary_db" {
  provider = aws.main
  zone_id  = aws_route53_zone.main.zone_id
  name     = "primary.mydomain.com"
  type     = "CNAME"
  ttl      = "60"
  records  = [aws_rds_cluster.primary.endpoint]
  weighted_routing_policy {
    weight = 70
  }
}

resource "aws_route53_record" "replica_us_east_db" {
  provider = aws.us-east
  zone_id  = aws_route53_zone.main.zone_id
  name     = "replica-us-east.mydomain.com"
  type     = "CNAME"
  ttl      = "60"
  records  = [aws_rds_cluster_instance.replica_us_east.endpoint]
  weighted_routing_policy {
    weight = 10
  }
}

resource "aws_route53_record" "replica_eu_central_db" {
  provider = aws.eu-central
  zone_id  = aws_route53_zone.main.zone_id
  name     = "replica-eu-central.mydomain.com"
  type     = "CNAME"
  ttl      = "60"
  records  = [aws_rds_cluster_instance.replica_eu_central.endpoint]
  weighted_routing_policy {
    weight = 10
  }
}

resource "aws_route53_record" "replica_ap_southeast_db" {
  provider = aws.ap-southeast
  zone_id  = aws_route53_zone.main.zone_id
  name     = "replica-ap-southeast.mydomain.com"
  type     = "CNAME"
  ttl      = "60"
  records  = [aws_rds_cluster_instance.replica_ap_southeast.endpoint]
  weighted_routing_policy {
    weight = 10
  }
}
```

This configuration includes:

- Providers for each AWS region.
- RDS clusters and instances for the primary and replica databases.
- A Route 53 hosted zone and CNAME records with weighted routing policy to distribute traffic. The primary DB carries the heaviest load with a weight of 70, while each replica has a weight of 10. Adjust these weights as per your load balancing requirement. 

Make sure to adjust parameters such as `mydb`, `dbadmin`, `SuperSecretPassword`, `my-dbsubnet-group`, etc., according to your specific deployment scenario.

