  zone_id = aws_route53_zone.public.zone_id
  name    = "public-db.example.com"
  type    = "CNAME"
  ttl     = "300"
  records = [aws_db_instance.public.address]
}

# Route 53 Record for Internal DB (Internal Endpoint)
