    target_group_arn = aws_lb_target_group.internal_rds_tg.arn
  }
}

resource "aws_lb_target_group" "internal_rds_tg" {
  name     = "internal-rds-tg"
  port     = 3306
  protocol = "TCP"
  vpc_id   = aws_vpc.my_vpc.id
  target_type = "ip"
