}


resource "aws_s3_bucket" "sample_bucket" {
  bucket_prefix = "sample-"
}

resource "aws_s3_object" "examplebucket_object" {
  key    = "randofile"
  bucket = aws_s3_bucket.sample_bucket.id
  source = "./supplement/app.zip"
}

# Define the Elastic Beanstalk application
resource "aws_elastic_beanstalk_application" "batch_job_app" {
  name        = "batch-job-application"
}

# Define the Elastic Beanstalk application version
resource "aws_elastic_beanstalk_application_version" "version" {
  name        = "batch-job-app-version"
  application = aws_elastic_beanstalk_application.batch_job_app.name
  bucket = aws_s3_object.examplebucket_object.bucket
  key    = aws_s3_object.examplebucket_object.key
}

# Create an Elastic Beanstalk environment in the worker tier
resource "aws_elastic_beanstalk_environment" "batch_job_env" {
  name                = "batch-job-environment"
  application         = aws_elastic_beanstalk_application.batch_job_app.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.3.0 running Python 3.9"
  tier                = "Worker"
  version_label       = aws_elastic_beanstalk_application_version.version.name

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "EnvironmentType"
    value     = "SingleInstance" 
  }

  setting {
    namespace = "aws:elasticbeanstalk:sqsd"
    name      = "WorkerQueueURL"
    value     = aws_sqs_queue.batch_job_queue.id 
  }

  setting {
    namespace = "aws:elasticbeanstalk:sqsd"
    name      = "HttpPath"
    value     = "/"
  }

  setting {
    namespace = "aws:elasticbeanstalk:sqsd"
    name      = "MimeType"
    value     = "application/json" 
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }
}

# Define the SQS queue
resource "aws_sqs_queue" "batch_job_queue" {
  name = "batch-job-queue"
}

response:
To create an Elastic Beanstalk worker environment for running batch processing jobs, we'll define several components in Terraform:

1. **IAM Role**: This will allow ES instances to perform actions on AWS resources.
2. **Instance Profile**: Attaches the IAM role to EC2 instances.
3. **S3 Bucket Object**: Your code package in S3.
4. **SNS Topic and Subscription**: For notifying worker environment changes.
5. **SQS Queue**: For task routing to worker instances.
6. **Elastic Beanstalk Application and Environment**: Sets up the worker environment.

Let's go ahead and set up the configuration:

```hcl
provider "aws" {
  region = "us-west-2" // Choose your appropriate region
}

resource "aws_iam_role" "eb_ec2_role" {
  name = "eb_ec2_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "ec2.amazonaws.com"
        },
        Effect = "Allow"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "eb_ec2_policy" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWorkerTier"
}

resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "eb_ec2_profile"
  role = aws_iam_role.eb_ec2_role.name
}

resource "aws_sqs_queue" "batch_job_queue" {
  name = "batch_job_queue"
}

resource "aws_s3_bucket" "bucket" {
  bucket = "sampleapril26426"
}

resource "aws_s3_bucket_object" "examplebucket_object" {
  bucket = aws_s3_bucket.bucket.bucket
  key    = "examplebucket_object"
  source = "path_to_your_code_package.zip" // Specify the path to your zipped application code
}

resource "aws_sns_topic" "eb_events" {
  name = "eb-events"
}

resource "aws_sqs_queue_policy" "sqs_policy" {
  queue_url = aws_sqs_queue.batch_job_queue.id

  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Sid       = "AllowSNSMessagesToSQS",
        Effect    = "Allow",
        Principal = {
          AWS = "*"
        },
        Action    = "sqs:SendMessage",
        Resource  = aws_sqs_queue.batch_job_queue.arn,
        Condition = {
          ArnEquals = {
            "aws:SourceArn" = aws_sns_topic.eb_events.arn
          }
        }
      }
    ]
  })
}

resource "aws_sns_topic_subscription" "eb_events_subscription" {
  topic_arn = aws_sns_topic.eb_events.arn
  protocol  = "sqs"
  endpoint  = aws_sqs_queue.batch_job_queue.arn
}

resource "aws_s3_bucket_notification" "bucket_notification" {
  bucket = aws_s3_bucket.bucket.bucket

  queue {
    queue_arn = aws_sqs_queue.batch_job_queue.arn
    events    = ["s3:ObjectCreated:*"]
    filter {
      key = {
        filter_rule {
          name = "prefix"
          value = ""
        }

        filter_rule {
          name = "suffix"
          value = ".zip"
        }
      }
    }
  }
}

resource "aws_elastic_beanstalk_application" "batch_job_app" {
  name = "batch_job_app"
}

resource "aws_elastic_beanstalk_application_version" "app_version" {
  name        = "version"
  application = aws_elastic_beanstalk_application.batch_job_app.name
  bucket      = aws_s3_bucket.bucket.bucket
  key         = aws_s3_bucket_object.examplebucket_object.key
}

resource "aws_elastic_beanstalk_environment" "worker_env" {
  name                = "batch_worker_env"
  application         = aws_elastic_beanstalk_application.batch_job_app.name
  solution_stack_name = "64bit Amazon Linux 2 v3.3.6 running Node.js 14"

  setting {
    namespace = "aws:ec2:vpc"
    name      = "VPCId"
    value     = "your_vpc_id" // Replace with your VPC ID
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }

  setting {
    namespace = "aws:elasticbeanstalk:command"
    name      = "BatchSize"
    value     = "1"
  }

  setting {
    namespace = "aws:elasticbeanstalk:command"
    name      = "DeploymentPolicy"
    value     = " Immutable"
  }

  setting {
    namespace = "aws:elasticbeanstalk:sqsd"
    name      = "Enabled"
    value     = "true"
  }

  setting {
    namespace = "aws:elasticbeanstalk:sqsd"
    name      = "EnvironmentType"
    value     = "Simple"
  }

  setting {
    namespace = "aws:elasticbeanstalk:sqsd"
    name      = "Value Stream"
    value     = "aws_sqs"
  }

  setting {
    namespace = "aws:elasticbeanstalk:sqsd"
    name      = "WorkerQueueURL"
    value     = aws_sqs_queue.batch_job_queue.id
  }

  setting {
    namespace = "aws:elasticbeanstalk:sqsd"
    name      = "WorkerRetentionPeriod"
    value     = "86400"
  }

  setting {
    namespace = "aws:elasticbeanstalk:cloudwatch:logs"
    name      = "StreamLogs"
    value     = "true"
  }
}
```

Replace placeholders (`your_vpc_id`, `path_to_your_code_package.zip`) with actual values suited to your deployment. This Terraform configuration sets up an Elastic Beanstalk worker environment ready to process jobs from an SQS queue, with IAM roles and S3 object paths adjusted for real deployments.

