}


provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_iam_role" "eb_ec2_role" {
  name = "elastic_beanstalk_ec2_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Effect = "Allow",
        Principal = {
          Service = "ec2.amazonaws.com"
        },
      },
    ]
  })
}

# Attach the AWS managed policy for Elastic Beanstalk to the role
resource "aws_iam_role_policy_attachment" "eb_managed_policy" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}


# Create an instance profile tied to the role
resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "elastic_beanstalk_ec2_profile"
  role = aws_iam_role.eb_ec2_role.name
}


resource "aws_db_instance" "default" {
  allocated_storage    = 20
  storage_type         = "gp2"
  engine               = "mysql"
  engine_version       = "5.7"
  instance_class       = "db.t3.micro"
  username             = "user"
  password             = "mypassword"
  parameter_group_name = "default.mysql5.7"
  skip_final_snapshot  = true
}

resource "aws_s3_bucket" "sample_bucket" {
  bucket_prefix = "sample-"
}

resource "aws_s3_object" "examplebucket_object" {
  key    = "randofile"
  bucket = aws_s3_bucket.sample_bucket.id
  source = "./supplement/app.zip"
}

# Define the Elastic Beanstalk application
resource "aws_elastic_beanstalk_application" "default" {
  name        = "my-app"
  description = "My awesome application"
}

# Define the Elastic Beanstalk application version
resource "aws_elastic_beanstalk_application_version" "version" {
  name        = "app-version"
  application = aws_elastic_beanstalk_application.default.name
  bucket = aws_s3_object.examplebucket_object.bucket
  key    = aws_s3_object.examplebucket_object.key
}

resource "aws_elastic_beanstalk_environment" "default" {
  name                = "my-app-env"
  application         = aws_elastic_beanstalk_application.default.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.3.0 running Python 3.9"

  setting {
    namespace = "aws:ec2:vpc"
    name      = "ELBScheme"
    value     = "public"
  }

  setting {
    namespace = "aws:autoscaling:asg"
    name      = "MinSize"
    value     = "1"
  }

  setting {
    namespace = "aws:autoscaling:asg"
    name      = "MaxSize"
    value     = "3"
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_USER"
    value     = aws_db_instance.default.username
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environmente"
    name      = "DB_PASSWORD"
    value     = aws_db_instance.default.password
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_HOST"
    value     = aws_db_instance.default.address
  }

  setting {
      namespace = "aws:autoscaling:launchconfiguration"
      name      = "IamInstanceProfile"
      value     = aws_iam_instance_profile.eb_ec2_profile.name
    }
}

response:
To configure an AWS Elastic Beanstalk environment that is linked to a relational database instance, we'll need to set up a few resources:

1. An S3 bucket to store the application version.
2. An Elastic Beanstalk application.
3. An Elastic Beanstalk environment.
4. A CloudFormation template for the Elastic Beanstalk environment that includes the relational DB instance.
5. Create an IAM instance profile, "eb_ec2_profile".

Below is the complete Terraform configuration in HCL format:

```hcl
provider "aws" {
  region = "us-east-1"
}

resource "aws_s3_bucket" "eb_bucket" {
  bucket = "elastic-beanstalk-app-bucket"
  acl    = "private"
}

data "aws_iam_policy_document" "ec2_policy" {
  statement {
    actions   = ["ec2:Describe*", "elasticbeanstalk:DescribeEvents"]
    resources = ["*"]
  }
}

resource "aws_iam_role" "eb_ec2_role" {
  name               = "EbEc2Role"
  assume_role_policy = data.aws_iam_policy_document.ec2_policy.json
}

resource "aws_iam_policy_attachment" "attach_role_policy" {
  name       = "EbAttachRolePolicy"
  roles      = [aws_iam_role.eb_ec2_role.name]
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSElasticBeanstalkWebTier"
}

resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "eb_ec2_profile"
  role = aws_iam_role.eb_ec2_role.name
}

resource "aws_iam_role_policy" "rds_access" {
  name = "EbRdsAccessPolicy"
  role = aws_iam_role.eb_ec2_role.id

  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "rds:DescribeDBInstances",
          "rds:ListTagsForResource",
          "rds:SelectInstanceTags"
        ],
        Resource = "*"
      },
    ]
  })
}

resource "aws_elastic_beanstalk_application" "app" {
  name        = "my-application"
  description = "My Elastic Beanstalk Application"
}

resource "aws_elastic_beanstalk_application_version" "app_version" {
  name        = "v1"
  application = aws_elastic_beanstalk_application.app.name
  bucket      = aws_s3_bucket.eb_bucket.bucket
  key         = "app-version.zip"
}

resource "aws_elastic_beanstalk_environment" "env" {
  name                = "my-environment"
  application         = aws_elastic_beanstalk_application.app.name
  solution_stack_name = "64bit Amazon Linux 2 v5.4.4 running Node.js 14"
  version_label       = aws_elastic_beanstalk_application_version.app_version.name

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.arn
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "VPCId"
    value     = "vpc-yourvpcid"
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "Subnets"
    value     = "subnet-yoursubnetid"
  }

  setting {
    namespace = "aws:elasticbeanstalk:database:credentials"
    name      = "DBUsername"
    value     = "admin"
  }

  setting {
    namespace = "aws:elasticbeanstalk:database:credentials"
    name      = "DBPassword"
    value     = "yourDBPassword"
  }

  setting {
    namespace = "aws:elasticbeanstalk:dbinstance"
    name      = "DBEngine"
    value     = "mysql"
  }

  setting {
    namespace = "aws:elasticbeanstalk:dbinstance"
    name      = "DBEngineVersion"
    value     = "5.7.22"
  }

  setting {
    namespace = "aws:elasticbeanstalk:dbinstance"
    name      = "DBInstanceClass"
    value     = "db.t2.micro"
  }

  setting {
    namespace = "aws:elasticbeanstalk:dbinstance"
    name      = "DBName"
    value     = "mydb"
  }

  setting {
    namespace = "aws:elasticbeanstalk:dbinstance"
    name      = "DBUser"
    value     = "admin"
  }

  setting {
    namespace  = "aws:rds:dbinstance"
    name       = "DBSecurityGroups"
    value      = "default"
  }

  setting {
    namespace  = "aws:elasticbeanstalk:application:environment"
    name       = "RDS_HOST"
    value      = "${aws_elastic_beanstalk_environment.env.name}.clouddb.amazonaws.com"
  }
}

output "environment_url" {
  value = aws_elastic_beanstalk_environment.env.cname
}
```

### Key Points:
- Ensure you choose suitable VPC and subnet configurations for your environment.
- Store your application bundle in the specified S3 bucket (`app-version.zip`).
- Customize the RDS settings such as username, password, and RDS security groups.
- Depending on your specific use case, additional security and configuration settings may be needed.

