}

resource "aws_iam_role_policy_attachment" "elastic_beanstalk_service_policy" {
  role       = aws_iam_role.elastic_beanstalk_service_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkFullAccess"
}

resource "aws_elastic_beanstalk_application" "my_app" {
  name        = "my-application"
  description = "An example application running on Elastic Beanstalk"
}

resource "aws_elastic_beanstalk_environment" "my_env" {
  name                = "my-env"
  application         = aws_elastic_beanstalk_application.my_app.name
  solution_stack_name = "64bit Amazon Linux 2 v3.1.3 running Python 3.8"
  tier                = "WebServer"

  setting {
    namespace = "aws:ec2:vpc"
    name      = "VPCId"
    value     = aws_vpc.main.id
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "Subnets"
    value     = "${aws_subnet.public_subnet1.id},${aws_subnet.public_subnet2.id}"
  }

  setting {
    namespace = "aws:elbv2:crosszone-load-balancing"
    name      = "Enabled"
    value     = "true"
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_role.elastic_beanstalk_service_role.name
  }
}

