}

# Attach the AWS managed policy for Elastic Beanstalk to the role
resource "aws_iam_role_policy_attachment" "eb_managed_policy" {
  provider = aws.us_east_1
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}


# Create an instance profile tied to the role
resource "aws_iam_instance_profile" "eb_ec2_profile" {
  provider = aws.us_east_1
  name = "elastic_beanstalk_ec2_profile"
  role = aws_iam_role.eb_ec2_role.name
}

# RDS in US East (N. Virginia)
resource "aws_db_instance" "main_db_us_east" {
  provider             = aws.us_east_1
  allocated_storage    = 20
  storage_type         = "gp2"
  engine               = "mysql"
  engine_version       = "5.7"
  instance_class       = "db.t3.micro"
  username             = "dbadmin"
  password             = "mysecurepassword"
  parameter_group_name = "default.mysql5.7"
  skip_final_snapshot  = true
  multi_az             = true
}

# Elastic Beanstalk Application in US East
resource "aws_elastic_beanstalk_application" "myapp_us_east" {
  provider = aws.us_east_1
  name     = "my-application-us-east"
}

# Elastic Beanstalk Environment in US East
resource "aws_elastic_beanstalk_environment" "myenv_us_east" {
  provider            = aws.us_east_1
  name                = "my-application-env-us-east"
  application         = aws_elastic_beanstalk_application.myapp_us_east.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.3.0 running Python 3.9"

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_HOST"
    value     = aws_db_instance.main_db_us_east.address
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_USERNAME"
    value     = aws_db_instance.main_db_us_east.address
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_PASSWORD"
    value     = aws_db_instance.main_db_us_east.address
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }
}

# RDS in EU West (Ireland)
resource "aws_db_instance" "main_db_eu_west" {
  provider             = aws.eu_west_1
  allocated_storage    = 20
  storage_type         = "gp2"
  engine               = "mysql"
  engine_version       = "5.7"
  instance_class       = "db.t3.micro"
  multi_az             = true
  username             = "dbadmin"
  password             = "mysecurepassword"
  parameter_group_name = "default.mysql5.7"
  skip_final_snapshot  = true
}

# Elastic Beanstalk Application in EU West
resource "aws_elastic_beanstalk_application" "myapp_eu_west" {
  provider = aws.eu_west_1
  name     = "my-application-eu-west"
}

# Elastic Beanstalk Environment in EU West
resource "aws_elastic_beanstalk_environment" "myenv_eu_west" {
  provider            = aws.eu_west_1
  name                = "my-application-env-eu-west"
  application         = aws_elastic_beanstalk_application.myapp_eu_west.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.3.0 running Python 3.9"

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_HOST"
    value     = aws_db_instance.main_db_eu_west.address
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_USERNAME"
    value     = aws_db_instance.main_db_eu_west.address
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_PASSWORD"
    value     = aws_db_instance.main_db_eu_west.address
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }
}

# Main Route 53 Hosted Zone
resource "aws_route53_zone" "main" {
  provider = aws.us_east_1
  name = "myapp.com"
}

# Latency Based Routing in Route 53 for US East Elastic Beanstalk Environment
resource "aws_route53_record" "eb_env_us_east" {
  provider = aws.us_east_1
  zone_id = aws_route53_zone.main.zone_id
  name    = "us-east.myapp.com"
  type    = "CNAME"
  ttl     = "60"
  records = [aws_elastic_beanstalk_environment.myenv_us_east.cname]
  set_identifier = "EastEnv"
  latency_routing_policy {
    region = "us-east-1"
  }
}

resource "aws_route53_record" "eb_env_eu_west" {
  provider = aws.eu_west_1
  zone_id = aws_route53_zone.main.zone_id
  name    = "eu-west.myapp.com"
  type    = "CNAME"
  ttl     = "60"
  records = [aws_elastic_beanstalk_environment.myenv_eu_west.cname]
  set_identifier = "WestEnv"
  latency_routing_policy {
    region = "eu-west-1"
  }
}

response:
To fulfill this request, we need to deploy AWS resources including Elastic Beanstalk environments, Amazon RDS databases, and Route 53 records across two regions ("us-east-1" and "eu-west-1"). We'll connect the configurations step by step to ensure we have all the necessary components. Here's how we'll organize the infrastructure:

1. **Elastic Beanstalk Environments**: Define two environments in their respective regions.
2. **RDS Databases**: Set up RDS databases in each region for the respective applications.
3. **Instance Profile**: Create an instance profile for the Elastic Beanstalk instances.
4. **Route 53 Domain and Records**: Route traffic to the appropriate Elastic Beanstalk applications using Route 53.

Below is the complete Terraform configuration for this request:

```hcl
provider "aws" {
  alias  = "us_east"
  region = "us-east-1"
}

provider "aws" {
  alias  = "eu_west"
  region = "eu-west-1"
}

resource "aws_iam_role" "eb_role" {
  name = "eb_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "elasticbeanstalk.amazonaws.com"
        }
        Action = "sts:AssumeRole"
      },
    ]
  })
}

resource "aws_iam_role_policy_attachment" "eb" {
  role       = aws_iam_role.eb_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

resource "aws_iam_instance_profile" "eb_ec2_profile3" {
  name = "eb_ec2_profile3"
  role = aws_iam_role.eb_role.name
}

resource "aws_elastic_beanstalk_environment" "myenv_us_east" {
  provider = aws.us_east

  name                = "myenv_us_east"
  application         = "myapp_us_east"
  solution_stack_name = "64bit Amazon Linux 2 v3.3.6 running Node.js 16"
  tier                = "WebServer"

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile3.name
  }
}

resource "aws_rds_cluster_instance" "main_db_us_east" {
  provider = aws.us_east

  identifier              = "main-db-us-east"
  cluster_identifier      = "main_cluster_us_east"
  instance_class          = "db.t3.micro"
  engine                  = "aurora-postgresql"
  engine_version          = "13.3"
  db_subnet_group_name    = aws_db_subnet_group.main_us_east.name
  publicly_accessible     = true
}

resource "aws_db_subnet_group" "main_us_east" {
  provider = aws.us_east

  name       = "main_subnet_group_us_east"
  subnet_ids = [var.us_east_subnet_id]
}

resource "aws_elastic_beanstalk_environment" "myenv_eu_west" {
  provider = aws.eu_west

  name                = "myenv_eu_west"
  application         = "myapp_eu_west"
  solution_stack_name = "64bit Amazon Linux 2 v3.3.6 running Node.js 16"
  tier                = "WebServer"

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile3.name
  }
}

resource "aws_rds_cluster_instance" "main_db_eu_west" {
  provider = aws.eu_west

  identifier              = "main-db-eu-west"
  cluster_identifier      = "main_cluster_eu_west"
  instance_class          = "db.t3.micro"
  engine                  = "aurora-postgresql"
  engine_version          = "13.3"
  db_subnet_group_name    = aws_db_subnet_group.main_eu_west.name
  publicly_accessible     = true
}

resource "aws_db_subnet_group" "main_eu_west" {
  provider = aws.eu_west

  name       = "main_subnet_group_eu_west"
  subnet_ids = [var.eu_west_subnet_id]
}

resource "aws_route53_zone" "main" {
  name = "example.com"
}

resource "aws_route53_record" "us_east_record" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "us-east.example.com"
  type    = "CNAME"
  records = [aws_elastic_beanstalk_environment.myenv_us_east.cname]
  ttl     = "300"
}

resource "aws_route53_record" "eu_west_record" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "eu-west.example.com"
  type    = "CNAME"
  records = [aws_elastic_beanstalk_environment.myenv_eu_west.cname]
  ttl     = "300"
}

variable "us_east_subnet_id" {
  description = "Subnet ID for us-east-1"
}

variable "eu_west_subnet_id" {
  description = "Subnet ID for eu-west-1"
}
```

### Notes:
- This configuration assumes you have provided subnet IDs for each region as Terraform variables (`us_east_subnet_id` and `eu_west_subnet_id`). Be sure to replace `"example.com"` in the `aws_route53_zone` resource with your actual domain.
- The `solution_stack_name` is based on a common Elastic Beanstalk setting. You might need to update it to match your specific requirements for the runtime or language version.

