      }
    ]
  })
}

resource "aws_iam_policy" "codebuild_policy" {
  name   = "example-codebuild-policy"
  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Effect = "Allow",
        Action = ["logs:CreateLogGroup", "logs:CreateLogStream", "logs:PutLogEvents"],
        Resource = "arn:aws:logs:*:*:*"
      },
      {
        Effect = "Allow",
        Action = ["s3:*"],
        Resource = [
          "arn:aws:s3:::example-unique-s3-bucket-name-for-codepipeline/*",
          "arn:aws:s3:::example-unique-s3-bucket-name-for-codepipeline",
        ]
      },
      {
        Effect = "Allow",
        Action = ["codebuild:BatchGetBuilds", "codebuild:StartBuild"],
        Resource = "*"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "codebuild_policy_attachment" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = aws_iam_policy.codebuild_policy.arn
}

resource "aws_cloudwatch_log_group" "codebuild_logs" {
  name = "/aws/codebuild/example-codebuild-project"
}

resource "aws_codebuild_project" "example_codebuild" {
  name          = "example-codebuild-project"
  description   = "Example CodeBuild project with GitHub source"
  service_role  = aws_iam_role.codebuild_role.arn
  build_timeout = "5"

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:4.0"
    type                        = "LINUX_CONTAINER"
    privileged_mode             = false
    environment_variable {
      name  = "VARIABLE_NAME"
      value = "example"
    }
  }

  source {
    type              = "GITHUB"
    location          = "https://github.com/yourusername/yourrepository"
    git_clone_depth   = 1
    buildspec         = "buildspec.yml"
    auth {
      type = "OAUTH"
    }
  }

  logs_config {
