    "I'd like to order a pizza",
    "I want to get a pizza",
    "Let's order a pizza"
  ]

  parent_bot_id = aws_lex_v2_bot.pizza_bot.id
  bot_version_id = aws_lex_v2_bot.pizza_bot.latest_version
}

