  }

  sample_utterance = "I want to cancel my order"
}

resource "aws_lex_intent" "modify_order" {
  name         = "ModifyOrder"
  fulfillment  {
    type = "ReturnIntent"
  }

  sample_utterance = "I need to make a change to my order"

  slot {
    name      = "Modification"
    type      = "AMAZON.Text"
    value_elicitation_required = true
    sample_utterance = "Change {Modification}"
  }

