resource "aws_kinesisanalyticsv2_application" "example" {
  name = "flink-analytics-application"

  service_execution_role = aws_iam_role.kinesis_analytics_role.arn

  dependson = [aws_kinesis_stream.example]

  vpc_config {
    security_group_ids = [aws_security_group.sg_example.id]
  }

  application_code = <<EOF
  CREATE OR REPLACE STREAM "DESTINATION_SQL_STREAM" (event VARCHAR(256));
  CREATE OR REPLACE PUMP "STREAM_PUMP" AS INSERT INTO "DESTINATION_SQL_STREAM"
  SELECT STREAM "event" FROM "SOURCE_SQL_STREAM_001";
  EOF

  inputs {
    name_prefix = "SOURCE_SQL_STREAM"
    enable_sagemaker_compatible_output = false

    kinesis_stream {
      resource_arn = aws_kinesis_stream.example.arn
    }

    reference_data_source {
      name    = "REFERENCE_DATA_SOURCE_001"
      mapping {
        reference_name = "environment"
        data_column = "environment"
        resource_arn = aws_kinesis_firehose_delivery_stream.reference.arn
