  name        = "firehose_policy"
  description = "A policy that allows Firehose to access S3 and other required AWS services"

  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action    = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ],
        Resource = [
