resource "aws_iam_policy" "firehose_policy" {
  name        = "firehose_policy"
  description = "A policy that allows Firehose to access S3 and other required AWS services"

  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action    = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ],
        Resource = [
          "${aws_s3_bucket.firehose_bucket.arn}",
          "${aws_s3_bucket.firehose_bucket.arn}/*"
        ],
        Effect = "Allow"
      },
      {
        Action    = [
          "logs:PutLogEvents"
        ],
        Resource = "arn:aws:logs:*:*:*",
        Effect = "Allow"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "firehose_policy_attachment" {
  role       = aws_iam_role.firehose_role.name
  policy_arn = aws_iam_policy.firehose_policy.arn
}

resource "aws_kinesis_firehose_delivery_stream" "firehose_stream" {
  name        = "my_firehose_stream"
  destination = "extended_s3"

  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.firehose_bucket.arn

    # Enable dynamic partitioning
    dynamic_partitioning_configuration {
      enabled = true
    }

    s3_backup_mode  = "FailedDocumentsOnly"
    buffer_size     = 10 # In MB
    buffer_interval = 300 # In seconds
  }
}
```

This configuration sets up:
- An S3 bucket to store Firehose delivered data.
- An IAM role and policy to allow Firehose to access the S3 bucket and CloudWatch Logs.
- A Kinesis Firehose Delivery Stream with dynamic partitioning enabled for the S3 destination. 

Make sure to replace names and policies as needed to suit your specific requirements and AWS environment.

