To create a Kinesis Firehose Delivery Stream with an Amazon Redshift cluster destination using Terraform, we need to consider the following:

1. **Redshift Cluster Setup**: We need to have a Redshift cluster configured, with necessary permissions for Kinesis Firehose to access it.
2. **Kinesis Firehose Delivery Stream**: Configure the Firehose delivery stream to point to the Redshift cluster.
3. **IAM Roles and Policies**: Create an IAM role for the Firehose to assume, with policies allowing access to Redshift.

Here's the Terraform configuration in HCL format:

```hcl
provider "aws" {
  region = "us-east-1"
}

resource "aws_redshift_cluster" "example" {
  cluster_identifier   = "example-cluster"
  database_name        = "exampledb"
  master_username      = "adminuser"
  master_password      = "YourSecurePassword!"
  node_type            = "dc2.large"
  cluster_type         = "multi-node"
  number_of_nodes      = 2
  publicly_accessible  = true

  # Additional configurations can be added here
}

resource "aws_iam_role" "firehose_role" {
  name = "firehose_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
        Action = "sts:AssumeRole"
      },
    ]
  })
}

resource "aws_iam_policy" "firehose_policy" {
  name = "firehose_redshift_policy"
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect    = "Allow"
        Action    = [
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource  = [
          "arn:aws:s3:::example-bucket",
          "arn:aws:s3:::example-bucket/*"
        ]
      },
      {
        Effect    = "Allow"
        Action    = [
          "redshift:DescribeClusterCredentials",
          "redshift:CreateClusterUser",
          "redshift:GrantClusterAccess",
          "redshift:RevokeClusterAccess",
          "redshift:DeleteClusterUser"
        ]
        Resource  = aws_redshift_cluster.example.arn
      },
      {
        Effect    = "Allow"
        Action    = [
          "redshift:CopyCommand",
          "redshift:DescribeStatement",
          "redshift:BatchGetStatementStatus"
        ]
        Resource  = "*"
      },
    ]
  })
}

resource "aws_iam_role_policy_attachment" "firehose_policy_attachment" {
  role       = aws_iam_role.firehose_role.name
  policy_arn = aws_iam_policy.firehose_policy.arn
}

resource "aws_kinesis_firehose_delivery_stream" "firehose_redshift" {
  name        = "example-firehose-redshift"
  destination = "redshift"

  redshift_configuration {
    role_arn           = aws_iam_role.firehose_role.arn
    cluster_jdbc_url   = "jdbc:redshift://example-cluster.example-redshift.us-east-1.redshift.amazonaws.com:5439/exampledb"
    copy_command {
      copy_ratio       = 1
      csv_delimiter    = ","
      record_format    = "CSV"
      enable_base64_encode = true
    }
    bucket_arn          = "arn:aws:s3:::example-bucket"
    table_name          = "example_table"
    s3_backup_mode      = "FailedRecord"

    s3_configuration {
      role_arn   = aws_iam_role.firehose_role.arn
      bucket_arn = "arn:aws:s3:::example-bucket"
    }
  }
}
```

### Key Points:
- Make sure to replace placeholders like `YourSecurePassword!` and example resource names (`example-cluster`, `example-bucket`, etc.) with actual values specific to your setup.
- Configure additional settings for Redshift and Firehose as needed, such as specific VPC configurations or additional security measures.
- Ensure that the IAM role has the necessary permissions to write to your S3 bucket (for failed records, if enabled) and Redshift cluster details are correct. 

This configuration governs how Kinesis Firehose will deliver data to an Amazon Redshift cluster, with the IAM role facilitating these operations.

