provider "aws" {
  region = "us-west-2"
}

resource "aws_iam_role" "firehose_role" {
  name = "firehose_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_policy" "firehose_policy" {
  name        = "firehose_policy"
  description = "Policy for Kinesis Firehose to access OpenSearch and S3"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "es:ESHttp*",
        ]
        Effect = "Allow"
        Resource = "arn:aws:es:us-west-2:123456789012:domain/my-opensearch-domain/*"
      },
      {
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject",
        ]
        Effect = "Allow"
        Resource = [
          "arn:aws:s3:::my-firehose-backup-bucket",
          "arn:aws:s3:::my-firehose-backup-bucket/*",
        ]
      },
    ]
  })
}

resource "aws_iam_role_policy_attachment" "firehose_policy_attachment" {
  role       = aws_iam_role.firehose_role.name
  policy_arn = aws_iam_policy.firehose_policy.arn
}

resource "aws_kinesis_firehose_delivery_stream" "firehose_to_opensearch" {
  name        = "firehose-to-opensearch"
  destination = "extended_s3"

  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = "arn:aws:s3:::my-firehose-backup-bucket"

    buffering_hints {
      size_in_m_bs = 5
      interval_in_secs = 300
    }

    cloudwatch_logging_options {
      enabled = true
      log_group_name = "/aws/kinesisfirehose/firehose-to-opensearch"
      log_stream_name = "firehose-to-opensearch-log-stream"
    }

    prefix        = "my-prefix/"
    error_output_prefix = "errors/"
  }

  s3_backup_mode    = "FailedRecordOnly"

  server_side_encryption { 
    type = "AES256"
  }

  datastore_vpc_configuration {
    vpc_id = "vpc-12345678"
  }

  opensearch_destination_configuration {
    domain_arn = "arn:aws:es:us-west-2:123456789012:domain/my-opensearch-domain"
    role_arn   = aws_iam_role.firehose_role.arn

    buffer_span = "900"

    cluster_endpoint = "my-opensearch-domain.us-west-2.es.amazonaws.com"

    index_name = "my-index"
    index_rotation_period = "OneDay"

    document_id_format_string = "[{firehose-generated-document-id}]"

    processing_configuration {
      processors {
        type = "Lambda"
        parameters = [
          {
            parameter_name = "LambdaArn"
            parameter_value = "arn:aws:lambda:us-west-2:123456789012:function:MyLambdaFunction"
          }
        ]
      }
    }

    retry_options {
      num_retries          = 5
      duration_secs        = 900
    }

    buffer_size = 5

    cloudwatch_logging_options {
      enabled             = true
      log_group_name      = "/aws/kinesisfirehose/my-opensearch-logging-group"
      log_stream_name     = "my-opensearch-logging-stream"
    }
  }

}

