terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}


resource "aws_s3_bucket" "januaryseventh" {
  bucket = "januaryseventh"
}

resource "aws_opensearch_domain" "test_cluster" {
  domain_name = "es-test-3"

  cluster_config {
    instance_count         = 2
    zone_awareness_enabled = true
    instance_type          = "m4.large.search"
  }

  ebs_options {
    ebs_enabled = true
    volume_size = 10
  }
}

data "aws_iam_policy_document" "firehose_assume_role" {
  statement {
    effect = "Allow"

    principals {
      type        = "Service"
      identifiers = ["firehose.amazonaws.com"]
    }

    actions = ["sts:AssumeRole"]
  }
}

resource "aws_iam_role" "firehose_role" {
  name               = "firehose_test_role"
  assume_role_policy = data.aws_iam_policy_document.firehose_assume_role.json
}

data "aws_iam_policy_document" "firehose-opensearch" {
  statement {
    effect  = "Allow"
    actions = ["es:*"]

    resources = [
      aws_opensearch_domain.test_cluster.arn,
      "${aws_opensearch_domain.test_cluster.arn}/*",
    ]
  }
}

resource "aws_iam_role_policy" "firehose-opensearch" {
  name   = "opensearch"
  role   = aws_iam_role.firehose_role.id
  policy = data.aws_iam_policy_document.firehose-opensearch.json
}

data "aws_iam_policy_document" "main" {
  statement {
    effect = "Allow"

    principals {
      type        = "*"
      identifiers = ["*"]
    }

    condition {
      test     = "IpAddress"
      variable = "aws:SourceIp"
      values   = ["127.0.0.1/32"]
    }

    actions   = ["es:*"]
    resources = ["${aws_opensearch_domain.test_cluster.arn}/*"]
  }
}

# applied at service level, necessary for opensearch access
resource "aws_opensearch_domain_policy" "main" {
  domain_name     = aws_opensearch_domain.test_cluster.domain_name
  access_policies = data.aws_iam_policy_document.main.json
}

resource "aws_kinesis_firehose_delivery_stream" "test" {
  depends_on = [aws_iam_role_policy.firehose-opensearch]

  name        = "terraform-kinesis-firehose-os"
  destination = "opensearch"

  opensearch_configuration {
    domain_arn = aws_opensearch_domain.test_cluster.arn
    role_arn   = aws_iam_role.firehose_role.arn
    index_name = "test"

    s3_configuration {
      role_arn   = aws_iam_role.firehose_role.arn
      bucket_arn = aws_s3_bucket.januaryseventh.arn
      buffering_size     = 10
      buffering_interval = 400
      compression_format = "GZIP"
    }
  }
}

response:
To create a Kinesis Firehose Delivery Stream with an OpenSearch destination in AWS using Terraform, follow these steps:

1. **Set Up the AWS Provider**: Define the AWS provider with the necessary region.

2. **Create an IAM Role**: Define an IAM role that Kinesis Firehose will assume to access other AWS services.

3. **Create an IAM Policy**: Create an IAM policy that permits necessary actions for Firehose to access OpenSearch and S3 for backups.

4. **Attach the IAM Policy**: Attach the IAM policy to the IAM role.

5. **Define an OpenSearch Domain**: Set up the OpenSearch domain. Note that for this implementation, we'll assume the domain is already created; you can define it similarly using Terraform if required.

6. **Create the Kinesis Firehose Delivery Stream**: Define the delivery stream with an OpenSearch destination, including necessary permissions and settings.

Here is the complete Terraform configuration:

```hcl
provider "aws" {
  region = "us-west-2"
}

resource "aws_iam_role" "firehose_role" {
  name = "firehose_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_policy" "firehose_policy" {
  name        = "firehose_policy"
  description = "Policy for Kinesis Firehose to access OpenSearch and S3"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "es:ESHttp*",
        ]
        Effect = "Allow"
        Resource = "arn:aws:es:us-west-2:123456789012:domain/my-opensearch-domain/*"
      },
      {
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject",
        ]
        Effect = "Allow"
        Resource = [
          "arn:aws:s3:::my-firehose-backup-bucket",
          "arn:aws:s3:::my-firehose-backup-bucket/*",
        ]
      },
    ]
  })
}

resource "aws_iam_role_policy_attachment" "firehose_policy_attachment" {
  role       = aws_iam_role.firehose_role.name
  policy_arn = aws_iam_policy.firehose_policy.arn
}

resource "aws_kinesis_firehose_delivery_stream" "firehose_to_opensearch" {
  name        = "firehose-to-opensearch"
  destination = "extended_s3"

  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = "arn:aws:s3:::my-firehose-backup-bucket"

    buffering_hints {
      size_in_m_bs = 5
      interval_in_secs = 300
    }

    cloudwatch_logging_options {
      enabled = true
      log_group_name = "/aws/kinesisfirehose/firehose-to-opensearch"
      log_stream_name = "firehose-to-opensearch-log-stream"
    }

    prefix        = "my-prefix/"
    error_output_prefix = "errors/"
  }

  s3_backup_mode    = "FailedRecordOnly"

  server_side_encryption { 
    type = "AES256"
  }

  datastore_vpc_configuration {
    vpc_id = "vpc-12345678"
  }

  opensearch_destination_configuration {
    domain_arn = "arn:aws:es:us-west-2:123456789012:domain/my-opensearch-domain"
    role_arn   = aws_iam_role.firehose_role.arn

    buffer_span = "900"

    cluster_endpoint = "my-opensearch-domain.us-west-2.es.amazonaws.com"

    index_name = "my-index"
    index_rotation_period = "OneDay"

    document_id_format_string = "[{firehose-generated-document-id}]"

    processing_configuration {
      processors {
        type = "Lambda"
        parameters = [
          {
            parameter_name = "LambdaArn"
            parameter_value = "arn:aws:lambda:us-west-2:123456789012:function:MyLambdaFunction"
          }
        ]
      }
    }

    retry_options {
      num_retries          = 5
      duration_secs        = 900
    }

    buffer_size = 5

    cloudwatch_logging_options {
      enabled             = true
      log_group_name      = "/aws/kinesisfirehose/my-opensearch-logging-group"
      log_stream_name     = "my-opensearch-logging-stream"
    }
  }

}
```

Replace the placeholder values (e.g., `arn:aws:es:`, bucket ARNs, VPC ID, and Lambda ARN) with your actual values. This configuration sets up the Firehose stream with all necessary roles and permissions to send data to an OpenSearch domain. Adjust settings like `role_arn`, `bucket_arn`, and OpenSearch domain details to match your environment.

