    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_kinesis_firehose_delivery_stream" "firehose_stream" {
  name = "my-firehose-stream"

  destination {
    elasticsearch_domain_arn = aws_elasticsearch_domain.es_domain.arn
    type = "elasticsearch"

    processing_configuration {
      processors = [
        {
          type = "Lambda"
          parameters = [
            {
              parameter_name = "LambdaArn"
              parameter_value = "arn:aws:lambda:us-east-1:123456789012:function:my-log-processing-function"
            }
          ]
