    kms_key_arn = "arn:aws:kms:us-east-1:123456789012:key/my-kms-key"
  }

  extended_s3_destination_configuration {
    role_arn = aws_iam_role.firehose_role.arn
    bucket_arn = "arn:aws:s3:::my-backup-bucket"
  }

  tags = {
