resource "aws_kinesisanalyticsv2_application" "firehose_delivery_stream" {
  name = "firehose-delivery-stream"

  delivery_stream_configuration = jsonencode({
    DeliveryStreamName        = "my-firesotre-opensearch"
    S3DestinationConfiguration = jsonencode({
      RoleARN = aws_iam_role.firehose_role.arn
