        SubnetIds = [aws_subnet.subnet1.id, aws_subnet.subnet2.id]
        SecurityGroupIds = ["sg-xxxxxxxx"] # Replace with your security group
      })
      ProcessingConfiguration = jsonencode({
        Enabled = true
        Processors = jsonencode([
          {
            Type           = "Lambda"
            Parameters     = jsonencode([
              {
                ParameterName = "LambdaArn"
                ParameterValue = "arn:aws:lambda:us-west-2:123456789012:function:my-lambda-function" # Replace with your Lambda ARN
              },
            ])
          }
        ])
      })
    })
  })
}

resource "aws_opensearch_domain" "opensearch_domain" {
  domain_name = "my-opensearch-cluster"

  cluster_config {
    instance_type = "t2.small.search"
