To create an AWS EKS node group with Terraform, we need to follow these steps:

1. **Define the EKS Cluster**: Assume the EKS cluster is already created.
2. **Define IAM Role and Policy Attachments**: Create an IAM role for the node group and attach necessary policies.
3. **Create the EKS Node Group**: Define the node group with required configurations.

Here's the complete Terraform configuration:

```hcl
provider "aws" {
  region = "us-west-2"
}

resource "aws_iam_role" "example_node_group" {
  name = "example-node-group-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
        Effect = "Allow"
        Sid    = ""
      },
    ]
  })
}

resource "aws_iam_role_policy_attachment" "example_worker_node_policy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSWorkerNodePolicy"
  role       = aws_iam_role.example_node_group.name
}

resource "aws_iam_role_policy_attachment" "example_cni_policy" {
  policy_arn = "arn:aws:iam::aws:policy/Amazon_EKS_CNI_Policy"
  role       = aws_iam_role.example_node_group.name
}

resource "aws_iam_role_policy_attachment" "example_ecr_read_only_policy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEC2ContainerRegistryReadOnly"
  role       = aws_iam_role.example_node_group.name
}

resource "aws_iam_instance_profile" "example_node_group" {
  name = "example-node-group-profile"
  role = aws_iam_role.example_node_group.name
}

resource "aws_eks_node_group" "example" {
  cluster_name    = aws_eks_cluster.example.name
  node_group_name = "example"
  node_role_arn   = aws_iam_role.example_node_group.arn
  subnet_ids      = ["subnet-12345678", "subnet-87654321"]

  scaling_config {
    desired_size = 1
    max_size     = 2
    min_size     = 1
  }

  update_config {
    max_unavailable = 1
  }

  instance_types = ["t3.medium"]

  depends_on = [
    aws_iam_role_policy_attachment.example_worker_node_policy,
    aws_iam_role_policy_attachment.example_cni_policy,
    aws_iam_role_policy_attachment.example_ecr_read_only_policy
  ]
}

resource "aws_eks_cluster" "example" {
  name     = "example"
  # Ensure the cluster exists and is properly configured
  # Add other necessary configurations like role_arn, version, etc.
}
```

### Key Points:

- **IAM Role and Policies**: Ensures that the node group has the necessary permissions.
- **Node Group Configuration**: Sets scaling parameters and update settings.
- **Dependencies**: Ensures IAM policies are attached before the node group is created. Adjust the `subnet_ids` and `instance_types` as per your infrastructure requirements.

