provider "aws" {
    region = "us-west-1"
}

data "aws_iam_policy_document" "topic" {
  statement {
    effect = "Allow"

    principals {
      type        = "Service"
      identifiers = ["s3.amazonaws.com"]
    }

    actions   = ["SNS:Publish"]
    resources = ["arn:aws:sns:*:*:s3-event-notification-topic"]

    condition {
      test     = "ArnLike"
      variable = "aws:SourceArn"
      values   = [aws_s3_bucket.bucket.arn]
    }
  }
}
resource "aws_sns_topic" "topic" {
  name   = "s3-event-notification-topic"
  policy = data.aws_iam_policy_document.topic.json
}

resource "aws_s3_bucket" "bucket" {
  bucket = "your-bucket-name"
}

resource "aws_s3_bucket_notification" "bucket_notification" {
  bucket = aws_s3_bucket.bucket.id

  topic {
    topic_arn     = aws_sns_topic.topic.arn
    events        = ["s3:ObjectCreated:*"]
    filter_suffix = ".log"
  }
}

response:
To address the request, we will follow these steps:

1. **Create an SNS Topic**: We'll create an SNS topic named `s3-event-notification-topic`.
2. **Create an S3 Bucket**: We'll create an S3 bucket named `your-bucket-name`.
3. **Create an IAM Policy for S3 to SNS Notification**: We'll set up an IAM policy that allows the `s3.amazonaws.com` service to publish to the SNS topic. This policy will include a condition to allow action only if the source ARN matches the S3 bucket's ARN with the specified event.
4. **Configure S3 Bucket Notification**: We'll set up an S3 bucket notification configuration to send events to the SNS topic for any new object created with a `.log` file extension.

Here's the Terraform configuration:

```hcl
provider "aws" {
  region = "us-west-2"
}

resource "aws_sns_topic" "s3_event_notification_topic" {
  name = "s3-event-notification-topic"
}

resource "aws_s3_bucket" "your_bucket_name" {
  bucket = "your-bucket-name"
}

data "aws_iam_policy_document" "s3_sns_publish" {
  statement {
    actions   = ["SNS:Publish"]
    resources = [aws_sns_topic.s3_event_notification_topic.arn]
    effect    = "Allow"

    principals {
      type        = "Service"
      identifiers = ["s3.amazonaws.com"]
    }

    condition {
      test     = "StringLike"
      variable = "aws:SourceArn"
      values   = ["arn:aws:s3:::your-bucket-name/*"]
    }
  }
}

resource "aws_sns_topic_policy" "s3_sns_publish_policy" {
  arn    = aws_sns_topic.s3_event_notification_topic.arn
  policy = data.aws_iam_policy_document.s3_sns_publish.json
}

resource "aws_s3_bucket_notification" "notify_sns" {
  bucket = aws_s3_bucket.your_bucket_name.id

  topic {
    topic_arn = aws_sns_topic.s3_event_notification_topic.arn

    events = [
      "s3:ObjectCreated:*"
    ]

    filter_prefix = ""
    filter_suffix = ".log"
  }
}
```

### Key Points
- **SNS Topic**: Created with a name `s3-event-notification-topic`.
- **S3 Bucket**: Created with a name `your-bucket-name`.
- **IAM Policy**: Allows the `s3.amazonaws.com` service to publish to the SNS topic, with a condition that the source ARN must match the S3 bucket ARN.
- **Bucket Notification**: Configured to send notifications to the SNS topic when objects with a `.log` suffix are created.

