}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
}

resource "aws_subnet" "public" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.1.0/24"
  map_public_ip_on_launch = true
  availability_zone = "us-west-2a"
}

resource "aws_subnet" "private" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.2.0/24"
  availability_zone = "us-west-2a"
}

resource "aws_internet_gateway" "gw" {
  vpc_id = aws_vpc.main.id
}

resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.gw.id
  }
}

resource "aws_route_table_association" "public" {
  subnet_id      = aws_subnet.public.id
  route_table_id = aws_route_table.public.id
}

resource "aws_security_group" "allow_ssh" {
  vpc_id = aws_vpc.main.id

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_launch_template" "lt" {
  name_prefix   = "lt-aws-linux2-"
  image_id      = data.aws_ssm_parameter.amazon_linux_ami_id.value
  instance_type = "t3.micro"

  key_name    = "your-key-pair"
  vpc_security_group_ids = [aws_security_group.allow_ssh.id]

  network_interfaces {
    associate_public_ip_address = true
    subnet_id                   = aws_subnet.public.id
  }
}

resource "aws_ec2_fleet" "fleet" {
  target_capacity_spec {
    default_target_capacity_type = "on-demand"
    total_target_capacity        = 5

    on_demand_target_capacity = 5
  }

  target_capacity_spec {
    default_target_capacity_type = "spot"
    total_target_capacity        = 4

    spot_target_capacity = 4

    spot_price = "0.05"
    allocation_strategy = "lowest-price"
  }

  launch_template_config {
    launch_template_specification {
      launch_template_id      = aws_launch_template.lt.id
      version                 = "$Latest"
    }

    overrides {
      instance_type = "t3.micro"
    }

    overrides {
      subnet_id = aws_subnet.private.id
    }
  }
}
```

### Explanation:
- **Dynamic AMI Retrieval**: The `aws_ssm_parameter` data source retrieves the latest Amazon Linux 2 AMI ID.
- **VPC & Subnets**: A VPC is created with one public and one private subnet.
- **Internet Gateway**: Provides internet access to the public subnet.
- **Security Group** & **Launch Template**: Allows SSH access and standard instance configuration.
- **EC2 Fleet**: Configured with a mix of On-Demand and Spot Instances using a Launch Template. Adjust `spot_price` and `instance_type` as needed. 

