resource "aws_iam_role_policy_attachment" "dynamodb" {
  role       = aws_iam_role.lambda_exec.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonDynamoDBFullAccess" # Or more restrictive policy if needed
}

resource "aws_dynamodb_table" "example_table" {
  name           = "exampleTable"
  hash_key       = "Id"
  billing_mode   = "PROVISIONED"
  read_capacity  = 5
  write_capacity = 5

  attribute {
    name = "Id"
