To achieve this, we need to set up a few things:

1. **AWS Lambda Function**: Create the Lambda function itself.
2. **IAM Role**: Define an IAM role for the Lambda function to specify its permissions.
3. **AWS CloudWatch Event Rule**: Create a rule to trigger the Lambda function every 15 minutes.
4. **Lambda Permission**: Attach permission for CloudWatch Events to invoke the Lambda function.

Below is the Terraform configuration to meet these requirements:

```hcl
provider "aws" {
  region = "us-east-1"
}

resource "aws_iam_role" "lambda_role" {
  name = "lambda_execution_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "lambda.amazonaws.com"
      }
    }]
  })
}

resource "aws_iam_role_policy" "lambda_policy" {
  name = "lambda_policy"
  role = aws_iam_role.lambda_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "logs:*"
        ]
        Effect = "Allow"
        Resource = "arn:aws:logs:*:*:*"
      },
    ]
  })
}

resource "aws_lambda_function" "my_lambda" {
  function_name = "MyLambdaFunction"
  handler       = "index.handler"
  role          = aws_iam_role.lambda_role.arn
  runtime       = "nodejs14.x"

  # Assume we're using a local lambda.zip for simplicity
  filename         = "lambda.zip"
  source_code_hash = filebase64sha256("lambda.zip")
}

resource "aws_cloudwatch_event_rule" "every_15_minutes" {
  name                = "every-15-minutes"
  description         = "Triggers Lambda every 15 minutes"
  schedule_expression = "rate(15 minutes)"
}

resource "aws_cloudwatch_event_target" "lambda_target" {
  rule      = aws_cloudwatch_event_rule.every_15_minutes.name
  target_id = "MyLambda"
  arn       = aws_lambda_function.my_lambda.arn
}

resource "aws_lambda_permission" "allow_cloudwatch" {
  statement_id   = "AllowExecutionFromCloudWatch"
  action         = "lambda:InvokeFunction"
  function_name  = aws_lambda_function.my_lambda.function_name
  principal      = "events.amazonaws.com"
  source_arn     = aws_cloudwatch_event_rule.every_15_minutes.arn
}
```
This configuration will set up the necessary infrastructure to run an AWS Lambda function every 15 minutes using a CloudWatch Event. Adjust the Lambda runtime and handler as needed based on your actual function implementation.

