To create an `aws_sagemaker_notebook_instance` using Terraform, we need to perform the following steps:

1. **Setup Provider**: Define the AWS provider to manage resources on AWS.
2. **Create SageMaker Notebook Instance**: Specify the `aws_sagemaker_notebook_instance` resource with the desired instance type `ml.t2.medium`.

Now, let's construct the Terraform configuration in HCL:

```hcl
provider "aws" {
  region = "us-west-2" # You can change this to your preferred region
}

resource "aws_sagemaker_notebook_instance" "example" {
  name    = "example-notebook-instance"
  role_arn = aws_iam_role.sagemaker_role.arn
  instance_type = "ml.t2.medium"

  tags = {
    Name = "ExampleSageMakerNotebook"
  }
}

resource "aws_iam_role" "sagemaker_role" {
  name = "sagemaker-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
        Action = "sts:AssumeRole"
      }
    ]
  })

  inline_policy {
    name = "SageMakerPermissions"
    policy = jsonencode({
      Version = "2012-10-17"
      Statement = [
        {
          Effect = "Allow"
          Action = [
            "s3:*",
            "sagemaker:*"
          ]
          Resource = "*"
        }
      ]
    })
  }
}

```

