To fulfill the request, we need to create several components using Terraform for AWS:

1. **VPC and Subnets**: Define a VPC with a public and a private subnet.
2. **Security Groups and Internet Gateway**: Set up necessary security groups and an Internet Gateway for the VPC if needed.
3. **Route Tables**: Define appropriate route tables for public and private subnets.
4. **Launch Template**: Create a Launch Template for AWS Linux 2 instances.
5. **EC2 Fleet**: Configure an EC2 Fleet using the Launch Template with both On-Demand and Spot Instances.

Let's construct the Terraform configuration step by step:

```hcl
provider "aws" {
  region = "us-west-2"
}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  enable_dns_hostnames = true
  tags = {
    Name = "main"
  }
}

resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id
}

resource "aws_subnet" "public" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-west-2a"
  map_public_ip_on_launch = true

  tags = {
    Name = "public"
  }
}

resource "aws_subnet" "private" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-west-2b"

  tags = {
    Name = "private"
  }
}

resource "aws_security_group" "sg" {
  name        = "ec2-sg"
  description = "Allow inbound traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "allow-ssh"
  }
}

resource "aws_route_table" "public_route_table" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "public"
  }
}

resource "aws_route_table_association" "public_association" {
  subnet_id      = aws_subnet.public.id
  route_table_id = aws_route_table.public_route_table.id
}

resource "aws_route_table" "private_route_table" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block     = "0.0.0.0/0"
    nat_gateway_id = aws_nat_gateway.natg.id
  }

  tags = {
    Name = "private"
  }
}

resource "aws_eip" "nat_ip" {
  vpc = true
}

resource "aws_nat_gateway" "natg" {
  allocation_id = aws_eip.nat_ip.id
  subnet_id     = aws_subnet.public.id
}

resource "aws_route_table_association" "private_association" {
  subnet_id      = aws_subnet.private.id
  route_table_id = aws_route_table.private_route_table.id
}

resource "aws_launch_template" "lt" {
  name_prefix   = "lt-aws-linux2-"
  image_id      = data.aws_ami.latest_amazon_linux.id
  instance_type = "t3.micro"

  network_interfaces {
    associate_public_ip_address = false
    security_groups             = [aws_security_group.sg.id]
  }

  block_device_mappings {
    device_name = "/dev/sda1"

    ebs {
      volume_size = 8
      volume_type = "gp2"
    }
  }

  tag_specifications {
    resource_type = "instance"
    tags = {
      Name = "AWS Linux 2 Instance"
    }
  }
}

data "aws_ami" "latest_amazon_linux" {
  most_recent = true

  owners = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }
}

resource "aws_ec2_fleet" "fleet" {
  launch_template_config {
    launch_template_specification {
      launch_template_id = aws_launch_template.lt.id
      version            = "$Latest"
    }
    overrides {
      instance_type     = "t3.micro"
      subnet_id         = aws_subnet.public.id
      max_price         = "0.05"
      weight            = 1
    }

    overrides {
      instance_type     = "t3.micro"
      subnet_id         = aws_subnet.private.id
      max_price         = "0.02"
      weight            = 1
    }
  }

  target_capacity_specification {
    default_target_capacity_type = "spot"
    total_target_capacity        = 9
  }

  on_demand_options {
    allocation_strategy = "prioritized"
  }

  replacement_strategy {
    strategy = "lowest-price"
  }

  tags = {
    Name = "ec2-fleet-example"
  }
}
```

### Explanation

1. **VPC and Subnets**: The configuration includes a VPC with a public and private subnet, each with a specified CIDR block.

2. **Internet Gateway & NAT Gateway**: An Internet Gateway for public subnet and a NAT Gateway for private subnet.

3. **Security Group**: Security group allowing SSH access (port 22).

4. **Route Tables**: Sets up route tables for public and private subnets, enabling internet access for the public subnet and NAT access for the private.

5. **Launch Template**: Defines a launch template for the AMI of Amazon Linux 2 (latest version) with specific configurations such as instance type and block device.

6. **AWS EC2 Fleet**: Describes an EC2 Fleet using spot pricing strategy, which consists of both on-demand and spot instances as specified in terms of target capacity, with pricing overrides for different subnets.

