  }
}

resource "aws_subnet" "private1" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-west-2a" # Adjust based on requirement

  tags = {
    Name = "private-subnet-1"
  }
}

resource "aws_subnet" "private2" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-west-2b" # Adjust based on requirement

  tags = {
    Name = "private-subnet-2"
  }
}

resource "aws_security_group" "efs_sg" {
  name        = "efs-sg"
  description = "Allow NFS traffic to/from EFS"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 2049
    to_port     = 2049
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_efs_file_system" "efs" {
  creation_token = "my-efs"

  tags = {
    Name = "my-efs"
  }
}

resource "aws_efs_mount_target" "efs_mt1" {
  file_system_id  = aws_efs_file_system.efs.id
  subnet_id       = aws_subnet.private1.id
  security_groups = [aws_security_group.efs_sg.id]
}

resource "aws_efs_mount_target" "efs_mt2" {
  file_system_id  = aws_efs_file_system.efs.id
  subnet_id       = aws_subnet.private2.id
  security_groups = [aws_security_group.efs_sg.id]
}

resource "aws_security_group" "instance_sg" {
  name        = "instance-sg"
  description = "Security group for EC2 instances"
  vpc_id      = aws_vpc.main.id

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_instance" "instance1" {
  ami                         = data.aws_ami.amazon_linux.id // Change this to the latest CentOS or Ubuntu if prefered
  instance_type               = "t2.micro"
  subnet_id                   = aws_subnet.private1.id
  vpc_security_group_ids      = [aws_security_group.instance_sg.id]
  associate_public_ip_address = false

  tags = {
    Name = "Instance1"
  }
}

resource "aws_instance" "instance2" {
  ami                         = data.aws_ami.amazon_linux.id
  instance_type               = "t2.micro"
  subnet_id                   = aws_subnet.private2.id
  vpc_security_group_ids      = [aws_security_group.instance_sg.id]
  associate_public_ip_address = false

  tags = {
    Name = "Instance2"
  }
}

data "aws_ami" "amazon_linux" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }
}
```

### Notes:
- This code assumes the usage of the latest Amazon Linux 2 AMI. Modify the AMI data source filters for a different Linux distribution if required.
- Ensure the AWS region and VPC settings align with your infrastructure needs.
- Security group rules need adjustment based on environment policies.
- This setup assumes that instances will utilize user data or init scripts to mount the EFS and manage instance configurations related to file system operations.

