terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

# Create a Virtual Private Cloud (VPC)
resource "aws_vpc" "my_vpc" {
  cidr_block = "10.0.0.0/16"
}

data "aws_availability_zones" "azs" {
    state = "available"
}

# Create Public Subnet
resource "aws_subnet" "public_subnet" {
  vpc_id                  = aws_vpc.my_vpc.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = data.aws_availability_zones.azs.names[0]
  map_public_ip_on_launch = true
}

# Create Private Subnet
resource "aws_subnet" "private_subnet" {
  vpc_id            = aws_vpc.my_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = data.aws_availability_zones.azs.names[1]
}

# Create EC2 Placement Group
resource "aws_placement_group" "my_placement_group" {
  name     = "my-placement-group"
  strategy = "cluster"
}

# Create Security Group for EC2 instances
resource "aws_security_group" "ec2_sg" {
  vpc_id = aws_vpc.my_vpc.id
  name   = "ec2_sg"
}

data "aws_ami" "amzn2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["*ubuntu-noble-24.04-amd64-server-*"]
  }
}

# Create EC2 instances in the Placement Group in the Private Subnet
resource "aws_instance" "ec2_instance" {
  count           = 3
  ami             = data.aws_ami.amzn2.id
  instance_type   = "m5.large"
  subnet_id       = aws_subnet.private_subnet.id
  security_groups = [aws_security_group.ec2_sg.id]
  placement_group = aws_placement_group.my_placement_group.name
}

response:
To set up three EC2 instances within an EC2 placement group using cluster networking in AWS, we'll follow these steps:

1. **Create the Placement Group**: Use the `aws_ec2_placement_group` resource to create a cluster placement group.

2. **Create the EC2 Instances**: Use the `aws_instance` resource to create three EC2 instances and associate them with the placement group.

Here’s the final Terraform HCL configuration encapsulated in a Markdown code block:

```hcl
provider "aws" {
  region = "us-east-1"
}

resource "aws_ec2_placement_group" "cluster" {
  name     = "cluster-group"
  strategy = "cluster"
}

resource "aws_instance" "ec2_instance_1" {
  ami           = "ami-0c55b159cbfafe1f0" # Replace with the AMI ID you want to use
  instance_type = "t3.micro"
  placement {
    grouping_strategy = "cluster"
    cluster_id        = aws_ec2_placement_group.cluster.id
  }
}

resource "aws_instance" "ec2_instance_2" {
  ami           = "ami-0c55b159cbfafe1f0" # Replace with the AMI ID you want to use
  instance_type = "t3.micro"
  placement {
    grouping_strategy = "cluster"
    cluster_id        = aws_ec2_placement_group.cluster.id
  }
}

resource "aws_instance" "ec2_instance_3" {
  ami           = "ami-0c55b159cbfafe1f0" # Replace with the AMI ID you want to use
  instance_type = "t3.micro"
  placement {
    grouping_strategy = "cluster"
    cluster_id        = aws_ec2_placement_group.cluster.id
  }
}
```

### Notes:
- **AMI**: Replace `ami-0c55b159cbfafe1f0` with the actual AMI ID you want to use for your instances.
- **Region**: Adjust the `region` attribute in the provider block if you are deploying in a different AWS region.
- **Instance Type**: The `t3.micro` instance type is used here, but you can modify this based on your requirements.
- Ensure you have the necessary IAM permissions and the AWS CLI configured with your environment credentials.

