terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_vpc" "vpc" {
    cidr_block = "192.168.0.0/22"
}

data "aws_availability_zones" "azs" {
    state = "available"
}

resource "aws_subnet" "subnet_az1" {
    availability_zone = data.aws_availability_zones.azs.names[0]
    cidr_block = "192.168.0.0/24"
    vpc_id = aws_vpc.vpc.id
    map_public_ip_on_launch = true
}

resource "aws_subnet" "subnet_az2" {
    availability_zone = data.aws_availability_zones.azs.names[1]
    cidr_block = "192.168.1.0/24"
    vpc_id = aws_vpc.vpc.id
    map_public_ip_on_launch = true
}

resource "aws_subnet" "subnet_az3" {
    availability_zone = data.aws_availability_zones.azs.names[2]
    cidr_block = "192.168.2.0/24"
    vpc_id = aws_vpc.vpc.id
    map_public_ip_on_launch = true
}

resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.vpc.id
}

resource "aws_route_table" "main" {
  vpc_id = aws_vpc.vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.main.id
  }
}

resource "aws_route_table_association" "first" {
  subnet_id      = aws_subnet.subnet_az1.id
  route_table_id = aws_route_table.main.id
}

resource "aws_route_table_association" "second" {
  subnet_id      = aws_subnet.subnet_az2.id
  route_table_id = aws_route_table.main.id
}

resource "aws_route_table_association" "third" {
  subnet_id      = aws_subnet.subnet_az3.id
  route_table_id = aws_route_table.main.id
}

resource "aws_security_group" "sg" {
    vpc_id = aws_vpc.vpc.id
}

resource "aws_vpc_security_group_ingress_rule" "ingress1" {
  security_group_id = aws_security_group.sg.id
  cidr_ipv4 = "0.0.0.0/0"
  ip_protocol = "-1"
}

resource "aws_vpc_security_group_egress_rule" "egress1" {
  security_group_id = aws_security_group.sg.id
  cidr_ipv4         = "0.0.0.0/0"
  ip_protocol       = "-1"
}

resource "aws_msk_cluster" "example" {
    cluster_name = "example"
    kafka_version = "3.2.0"
    number_of_broker_nodes = 3

    broker_node_group_info {
        instance_type = "kafka.t3.small"
        client_subnets = [
            aws_subnet.subnet_az1.id,
            aws_subnet.subnet_az2.id,
            aws_subnet.subnet_az3.id,
        ]

        storage_info {
            ebs_storage_info {
                volume_size = 1000
            }
        }

        security_groups = [aws_security_group.sg.id]
    }

    open_monitoring {
        prometheus {
            jmx_exporter {
                enabled_in_broker = true
            }
            node_exporter {
                enabled_in_broker = true
            }
        }
    }

    logging_info {
        broker_logs {
            cloudwatch_logs {
                enabled = false
            }
            firehose {
                enabled = false
            }
            s3 {
                enabled = false
            }
        }
    }
}

output "zookeeper_connect_string" {
    value = aws_msk_cluster.example.zookeeper_connect_string
}

output "bootstrap_brokers_tls" {
    description = "TLS connection host:port pairs"
    value = aws_msk_cluster.example.bootstrap_brokers_tls
}

response:
To create a Microsoft Kubernetes Service (MSK) cluster with 3 broker nodes in Microsoft Azure, we need to set up the following resources using Terraform:

1. **Azure Kubernetes Service (AKS) Cluster**: Since you're referring to MSK with broker nodes, I believe you mean an Apache Kafka cluster, which can be managed in AKS using Koperator or a similar solution.
2. **Resource Group**: To manage and provision the necessary Azure resources.
3. **Virtual Network and Subnets**: For networking purposes.
4. **Managed Identity**: For authentication with Azure.
5. **Kubernetes Namespace**: To host the Kafka cluster.
6. **Kafka Resource**: Configuration of the Kafka cluster with 3 broker nodes using the Koperator CRD if used.

Below is a sample Terraform configuration capturing these steps. Since there isn't a direct MSK resource in Azure (as compared to AWS MSK), we will conceptualize a Kafka setup on AKS via Kubernetes resources.

```hcl
provider "azurerm" {
  features {}
}

resource "azurerm_resource_group" "example" {
  name     = "kafka-aks-rg"
  location = "East US"
}

resource "azurerm_virtual_network" "example" {
  name                = "vnet-kafka"
  address_space       = ["10.0.0.0/16"]
  location            = azurerm_resource_group.example.location
  resource_group_name = azurerm_resource_group.example.name
}

resource "azurerm_subnet" "example" {
  name                 = "subnet-kafka"
  resource_group_name  = azurerm_resource_group.example.name
  virtual_network_name = azurerm_virtual_network.example.name
  address_prefixes     = ["10.0.1.0/24"]
}

resource "azurerm_kubernetes_cluster" "example" {
  name                = "kafka-aks"
  location            = azurerm_resource_group.example.location
  resource_group_name = azurerm_resource_group.example.name
  dns_prefix          = "kafka"

  default_node_pool {
    name       = "default"
    node_count = 3
    vm_size    = "Standard_D2_v2"
    vnet_subnet_id = azurerm_subnet.example.id
  }

  identity {
    type = "SystemAssigned"
  }

  role_based_access_control {
    enabled = true
  }
}

resource "kubernetes_namespace" "kafka" {
  metadata {
    name = "kafka"
  }
}

resource "kubernetes_manifest" "kafka" {
  manifest = {
    apiVersion = "kafka.strimzi.io/v1beta1"
    kind       = "Kafka"
    metadata = {
      name      = "kafka-cluster"
      namespace = kubernetes_namespace.kafka.metadata[0].name
    }
    spec = {
      kafka = {
        replicas = 3
        listener = {
          name        = "plain"
          port        = 9092
          tlsDisabled = true
          type        = "internal"
        }
        config = {
          offsetsTopicReplicationFactor = 3
          transactionStateLogTopicReplicationFactor = 3
          transactionStateLogMinIsolation = "read_committed"
        }
        storage = {
          type = "ephemeral"
        }
      }
      zookeeper = {
        replicas = 3
        storage = {
          type = "ephemeral"
        }
      }
      entityOperator = {
        topicOperator = {}
        userOperator   = {}
      }
    }
  }
}

output "aks_cluster_name" {
  value = azurerm_kubernetes_cluster.example.name
}

output "aks_cluster_id" {
  value = azurerm_kubernetes_cluster.example.id
}

output "kubernetes_cluster_endpoint" {
  value = azurerm_kubernetes_cluster.example.kube_config[0].endpoint
}

output "kubernetes_cluster_ca_certificate" {
  value = base64decode(
    azurerm_kubernetes_cluster.example.kube_config[0].cluster_ca_certificate
  )
}
```

### Explanation:
- **Azure Resource Group**: The organizational structure for resources.
- **Virtual Network & Subnet**: Network isolation for the AKS cluster.
- **AKS Cluster**: A basic setup for hosting Kubernetes nodes.
- **Kubernetes Namespace**: A logical separator within the cluster.
- **Kafka Manifest**: Custom resource definition for deploying Kafka using Strimzi, equipped with 3 broker nodes and ephemeral storage.

This setup assumes you are using the Strimzi operator to manage Kafka clusters in Kubernetes. Adjustments may be required based on your specific use case or logic. Ensure Terraform and Azure CLI are properly configured to authenticate with your Azure subscription.

