response:
To create a managed MSK cluster with 3 broker nodes in the `us-east1` region on AWS, we need to define the following key components in our Terraform configuration:

1. **AWS Provider**: To specify the cloud provider context.
2. **VPC Configuration**: Create a VPC and subnets with proper networking in `us-east1` to host the MSK cluster, as MSK requires an existing Virtual Private Cloud (VPC).
3. **MSK Cluster**: Define the MSK cluster with 3 broker nodes.

Here is the step-by-step configuration in Terraform HCL:

```hcl
provider "aws" {
  region = "us-east-1"
}

resource "aws_vpc" "msk_vpc" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "msk_vpc"
  }
}

resource "aws_subnet" "msk_subnet_1" {
  vpc_id                  = aws_vpc.msk_vpc.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = false
}

resource "aws_subnet" "msk_subnet_2" {
  vpc_id                  = aws_vpc.msk_vpc.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-east-1b"
  map_public_ip_on_launch = false
}

resource "aws_subnet" "msk_subnet_3" {
  vpc_id                  = aws_vpc.msk_vpc.id
  cidr_block              = "10.0.3.0/24"
  availability_zone       = "us-east-1c"
  map_public_ip_on_launch = false
}

resource "aws_security_group" "msk_sg" {
  name        = "msk_sg"
  description = "Security Group for MSK Cluster"
  vpc_id      = aws_vpc.msk_vpc.id

  ingress {
    protocol    = "tcp"
    from_port   = 9092
    to_port     = 9092
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    protocol    = "-1"
    from_port   = 0
    to_port     = 0
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_iam_role" "msk_iam_role" {
  name = "MSKClusterRole"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "kafka.amazonaws.com"
        },
        Effect = "Allow",
        Sid = "",
      },
    ],
  })
}

resource "aws_iam_role_policy_attachment" "msk_iam_policy" {
  role       = aws_iam_role.msk_iam_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonMSKServicePolicy"
}

resource "aws_msk_cluster" "msk_cluster" {
  cluster_name           = "my-msk-cluster"
  kafka_version          = "2.8.0"
  number_of_broker_nodes = 3
  broker_node_group_info {
    ebs_volume_size            = 1000
    client_subnets             = [aws_subnet.msk_subnet_1.id, aws_subnet.msk_subnet_2.id, aws_subnet.msk_subnet_3.id]
    security_groups            = [aws_security_group.msk_sg.id]
    instance_type              = "kafka.m5.large"
    ebs_volume_type            = "gp3"
    provisioned_throughput     = 300
    client_enabled              = true
  }

  configuration_info {
    arn       = "${data.aws_msk_configuration.msk_config.arn}"
    revision  = "${data.aws_msk_configuration.msk_config.revision}"
  }
}

data "aws_msk_configuration" "msk_config" {
  name = "default-msk-configuration"
}
```

### Explanation:

- **VPC and Subnets**: We create a VPC and three subnets across different availability zones for high availability.
- **Security Group**: We set up a security group to allow traffic to the MSK broker ports (default is 9092).
- **IAM Role**: An IAM role with the necessary MSK policy is created.
- **MSK Cluster**: We define the MSK cluster with 3 broker nodes, specifying required configurations such as the Kafka version, EBS volume size, and instance type.
- **MSK Configuration**: We reference a managed MSK configuration to apply specific settings to our cluster.

Ensure you have the appropriate AWS credentials configured and AWS permissions to create these resources.

