response:
To create a managed Apache Kafka cluster with AWS MSK in the `us-east-1` region that logs to a CloudWatch Logs group, we'll follow these steps:

1. **Define the Provider**: Specify AWS as the provider and set the region to `us-east-1`.
2. **Create an IAM Role for MSK**: AWS MSK requires an IAM role to allow the MSK service to interact with other AWS services.
3. **Configure the CloudWatch Logs Group**: Define a CloudWatch Logs group where MSK will send its logs.
4. **Create the MSK Cluster**: Declare the managed MSK cluster, specifying logging configuration.

Here is the complete Terraform configuration in HCL:

```hcl
provider "aws" {
  region = "us-east-1"
}

resource "aws_iam_role" "msk_service" {
  name = "msk_service_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "msk.amazonaws.com"
        }
        Action = "sts:AssumeRole"
      },
    ]
  })
}

resource "aws_iam_role_policy" "msk_policy" {
  name = "msk_policy"
  role = aws_iam_role.msk_service.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogStream",
          "logs:PutLogEvents",
        ]
        Resource = "arn:aws:logs:*:*:*"
      },
    ]
  })
}

resource "aws_cloudwatch_log_group" "msk_logs" {
  name = "/aws/msk/my-cluster-logs"
}

resource "aws_msk_cluster" "my_cluster" {
  cluster_name             = "my-msk-cluster"
  kafka_version            = "2.8.1"
  number_of_broker_nodes   = 3
  enhanced_monitoring      = "PER_BROKER"
  broker_node_group_info {
    instance_type   = "kafka.m5.large"
    ebs_volume_size = 1000
    client_subnets  = ["subnet-12345678", "subnet-87654321"]  # Provide appropriate subnet IDs
  }
  logging_info {
    broker_logs {
      cloudwatch {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_logs.name
      }
    }
  }
  security_config {
    security_protocol = "PLAINTEXT"
    iam = "ENABLED"
  }
  cluster_configuration_overrides {
    "kafka Yellowstone Kafka" = jsonencode({
      "auto.create.topic.enable" = true
    })
  }
  role_arn = aws_iam_role.msk_service.arn
}
```

**Additional Notes:**
- Make sure to replace `client_subnets` with appropriate subnet IDs in your VPC.
- Modify `security_protocol` and configure additional security settings based on your security requirements.
- You can adjust `kafka_version`, `instance_type`, and `ebs_volume_size` based on your specific needs.

