    broker_logs {
      cloudwatch_log_group_arn = "arn:aws:logs:us-east-1:123456789012:log-group:/aws/kafka/example-msk-cluster"
      s3 {
        bucket = aws_s3_bucket.msk_logs.bucket
        prefix = "msk-cluster-logs/"
        enabled = true
      }
    }
  }

  enhanced_monitoring = ["PER_BROKER"]

  configuration_info {
    arn      = aws_msk_configuration.msk_conf.arn
    revision = aws_msk_configuration.msk_conf.latest_revision
  }
}

