To create a serverless MSK (Managed Streaming for Kafka) cluster with 3 broker nodes using Terraform, we need to follow these steps:

1. Set up the AWS provider in Terraform.
2. Define the resource for the MSK cluster with serverless configuration.

Here's the Terraform configuration for your request:

```hcl
provider "aws" {
  region = "us-east-1" # You can specify your desired AWS region here.
}

resource "aws_msk_cluster" "example" {
  cluster_name = "example-cluster"
  kafka_version = "2.8.0"
  number_of_broker_nodes = 3
  serverless_cluster_config {
    num_partitions_per_broker = 1
  }

  configuration_info {
    arn = "arn:aws:kafka:us-east-1:123456789012:configuration/example-configuration" # Replace with your configuration ARN
    revision = "1"
  }

  broker_node_group_info {
    instance_type   = "kafka.m5.xlarge"
    ebs_volume_size = 1000
  }

  cloudwatch_logs_insights_enabled = true
  enhanced_monitoring = "DEFAULT"
  kafka_broker_logs_s3_backup_mode = "ARCHIVE_TO_S3"
  open_monitoring_enabled = true
  open_monitoring_kafka_version = "2_3_4"
  processing_defaults {
    auto_create_topics_enable = true
    delete_retention_hours = 7
    faulty_node_detection_time_ms = 600000
    inter_broker_protocol_version = "2.8"
    log_message_format_version = "2.8"
    unclean_leader_election_enable = false
  }
  tagging {
    kafka_cluster = "example-cluster"
    kafka_broker = "broker"
    kafka_topic = "topic"
    kafka_user = "user"
  }

  topic_info {
    topic_name = "example-topic"
    num_partitions = 3
    partition_config {
      replication_factor = 3
    }
  }
}
```

### Key Points:

- **AWS Region**: You can change this according to your requirements.
