To create a serverless MSK (Managed Streaming for Apache Kafka) cluster in AWS with 3 broker nodes in the `us-east-1` region, you'll configure Terraform to automate this setup using the AWS provider.

Here are the steps to generate the Terraform configuration:

1. **Set up the AWS Provider**: Define the AWS provider and specify the `us-east-1` region.

2. **Define the MSK Cluster Resource**: Use the `aws_msk_cluster` resource to define the MSK cluster. Ensure the cluster configuration contains settings for a serverless MSK setup.

3. **Broker Configuration**: Configure the cluster to use serverless mode, which allows it to scale automatically without specifying a fixed number of brokers.

Let's create the final Terraform configuration in HCL:

```hcl
provider "aws" {
  region = "us-east-1"
}

resource "aws_msk_cluster" "example" {
  cluster_name   = "example-cluster"
  kafka_version  = "2.8.1"  # Use the desired Kafka version
  kafka_config   = {
    "auto.create.topics.enable" = "true"
  }

  storage_config {
    ebs_volume_size = 10
    volume_encryption = "true"
  }

  serverless_vpc_configuration {
    subnets = [
      "subnet-xxxxxxxx",   # Replace with the appropriate subnet ID
      "subnet-yyyyyyyy",
      "subnet-zzzzzzzz"
    ]
  }

  configuration_info {
    arn         = "arn:aws:kafka:us-east-1:123456789012:endpoint/example-cluster"  # Replace with appropriate ARN if needed
    revision    = 1
  }
}
```

### Notes:
- **Subnets**: Replace `"subnet-xxxxxxxx"`, `"subnet-yyyyyyyy"`, and `"subnet-zzzzzzzz"` with the actual subnet IDs in your VPC.
- **ARN**: The `configuration_info.arn` might not be necessary for a serverless MSK configuration. Verify based on your use case.
- **Kafka Version**: Ensure the `kafka_version` is set according to your application's compatibility.
- **Security and Permissions**: Ensure your AWS credentials and permissions are correctly set up to allow Terraform to manage AWS resources.

This configuration will result in an MSK cluster that scales automatically using the serverless settings, within the specified region and subnets.

extracted_code:
provider "aws" {
  region = "us-east-2"
}

resource "aws_msk_cluster" "serverless_msk_cluster" {
  cluster_name           = "serverless-msk-cluster"
  kafka_version          = "2.8.1"  // Adjust version as needed
  number_of_broker_nodes = 0  // For serverless mode

  kafka_config {
    "kafka-server-listeners" = "PLAINTEXT://:9092"
    "kafka-ads-listeners"    = "PLAINTEXT://:9093"
    "unauthenticated-listeners" = "PLAINTEXT://:9094"
  }

  client_authentication {
    tls {
      client_authentication_type = "TLS"
      tls_version                = "TLSv1_2"
      certificate_authority_arns = [aws_acm_certificate.example.arn]
    }
  }

  encryption_info {
    encryption_in_transit {
      client_broker = "TLS"
    }
  }

  open_monitoring {
    prometheus = {
      jmx_exporter = {
        enabled_in_broker = true
        tls = {
          client_authentication_type = "NONE"
        }
      }
    }
  }

  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = "/aws/msk/serverless_msk_cluster"
      }
    }
  }

  storage_role_arn = aws_iam_role.msk_storage.arn
  enhanced_monitoring = ["DEFAULT", "PER_BROKER"]

  kafka_broker_ids_info {
    broker_ids_info {
      id = 0
      storage {
        ebs_volume {
          volume_type = "gp2" // For initializing the cluster, though it's not used in serverless mode
          volume_size = 10
        }
        iops        = 100
        throughput_mode = "BURSTING"
      }
    }
  }

  client_authentication {
    tls {
      certificate_authority_arns = [aws_acm_certificate.example.arn]
      tls_version                = "TLSv1_2"
    }
  }
}

resource "aws_acm_certificate" "example" {
  domain_name       = "example.com" // Adjust the domain name to your specific needs
  validation_method = "DNS"
}

resource "aws_iam_role" "msk_storage" {
  name               = "mskStorageRole"
  assume_role_policy = jsonencode(
    {
      Version = "2012-10-17"
      Statement = [
        {
          Effect = "Allow"
          Principal = { Service = "kafka.amazonaws.com" }
          Action = "sts:AssumeRole"
        }
      ]
    }
  )
}

resource "aws_iam_policy" "msk_storage_policy" {
  name   = "mskStoragePolicy"
  policy = data.aws_iam_policy_document.msk_storage.json
}

data "aws_iam_policy_document" "msk_storage" {
  statement {
    sid = ""
    actions = [
      "kms:GenerateDataKey",
      "kms:Encrypt",
      "kms:Decrypt",
      "kms:ReEncrypt*",
      "kms:GenerateDataKeyWithoutPlaintext"
    ]
    resources = [
      "*"
    ]
  }
}

resource "aws_iam_role_policy_attachment" "msk_storage_policy_attachment" {
  role       = aws_iam_role.msk_storage.name
  policy_arn = aws_iam_policy.msk_storage_policy.arn
}

