To create a serverless MSK (Managed Streaming for Apache Kafka) cluster in AWS using Terraform, we need to define resources that specify the MSK cluster with `serverless` mode in the `us-east-2` (Ohio) region. Here’s the step-by-step process and the final Terraform code:

1. **Define the AWS Provider:**
   We need to specify the provider and region for the AWS services. In this case, we are using `us-east-2`.

2. **Configure the MSK Cluster:**
   We will create a `aws_msk_cluster` resource with the necessary configurations:
   - Set the mode to `serverless`.
   - Define the Kafka version.
   - Set the service type to `INTELLIGENT_TIERING` for serverless MSK.
   - Specify any additional settings such as logging configurations if needed.

Here is the final Terraform configuration in HCL format:

```hcl
provider "aws" {
  region = "us-east-2"
}

resource "aws_msk_cluster" "serverless_msk_cluster" {
  cluster_name           = "serverless-msk-cluster"
  kafka_version          = "2.8.1"  // Adjust version as needed
  number_of_broker_nodes = 0  // For serverless mode

  kafka_config {
    "kafka-server-listeners" = "PLAINTEXT://:9092"
    "kafka-ads-listeners"    = "PLAINTEXT://:9093"
    "unauthenticated-listeners" = "PLAINTEXT://:9094"
  }

  client_authentication {
    tls {
      client_authentication_type = "TLS"
      tls_version                = "TLSv1_2"
      certificate_authority_arns = [aws_acm_certificate.example.arn]
    }
  }

  encryption_info {
    encryption_in_transit {
      client_broker = "TLS"
    }
  }

  open_monitoring {
    prometheus = {
      jmx_exporter = {
        enabled_in_broker = true
        tls = {
          client_authentication_type = "NONE"
        }
      }
    }
  }

  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = "/aws/msk/serverless_msk_cluster"
      }
    }
  }

  storage_role_arn = aws_iam_role.msk_storage.arn
  enhanced_monitoring = ["DEFAULT", "PER_BROKER"]

  kafka_broker_ids_info {
    broker_ids_info {
      id = 0
      storage {
        ebs_volume {
          volume_type = "gp2" // For initializing the cluster, though it's not used in serverless mode
          volume_size = 10
        }
        iops        = 100
        throughput_mode = "BURSTING"
      }
    }
  }

  client_authentication {
    tls {
      certificate_authority_arns = [aws_acm_certificate.example.arn]
      tls_version                = "TLSv1_2"
    }
  }
}

resource "aws_acm_certificate" "example" {
  domain_name       = "example.com" // Adjust the domain name to your specific needs
  validation_method = "DNS"
}

resource "aws_iam_role" "msk_storage" {
  name               = "mskStorageRole"
  assume_role_policy = jsonencode(
    {
      Version = "2012-10-17"
      Statement = [
        {
          Effect = "Allow"
          Principal = { Service = "kafka.amazonaws.com" }
          Action = "sts:AssumeRole"
        }
      ]
    }
  )
}

resource "aws_iam_policy" "msk_storage_policy" {
  name   = "mskStoragePolicy"
  policy = data.aws_iam_policy_document.msk_storage.json
}

data "aws_iam_policy_document" "msk_storage" {
  statement {
    sid = ""
    actions = [
      "kms:GenerateDataKey",
      "kms:Encrypt",
      "kms:Decrypt",
      "kms:ReEncrypt*",
      "kms:GenerateDataKeyWithoutPlaintext"
