resource "aws_iam_role_policy_attachment" "msk_storage_policy_attachment" {
  role       = aws_iam_role.msk_storage.name
  policy_arn = aws_iam_policy.msk_storage_policy.arn
}
```

**Note:** This code includes resources for an IAM role and ACM certificate for TLS, which you can adjust based on your custom setup requirements. Replace placeholders like `example.com` with the actual domain name you intend to use. The MSK cluster is set to be serverless with logging configured to CloudWatch. The storage-related settings are included for compliance, even though they are not actually used in serverless mode. Adjust configurations as per your specific needs.

extracted_code:
provider "aws" {
  region = "us-west-2"
}

# KMS Key for encryption at rest
resource "aws_kms_key" "msk_encryption_key" {
  description             = "KMS key for MSK encryption at rest"
  deletion_window_in_days = 10
}

resource "aws_kms_alias" "msk_encryption_key_alias" {
  name          = "alias/msk_encryption_key"
  target_key_id = aws_kms_key.msk_encryption_key.key_id
}

# IAM Role for MSK with necessary policies
resource "aws_iam_role" "msk_role" {
  name = "msk_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "msk.amazonaws.com"
        }
      },
    ]
  })
}

# Attach policy for open monitoring
resource "aws_iam_policy" "msk_open_monitoring_policy" {
  name = "msk_open_monitoring_policy"
  description = "Allow MSK to use open monitoring features"

  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "apigateway:GET",
          "apigateway:POST",
          "apigateway:PUT",
          "lambda:*",
          "logs:*",
          "xray:PutTraceSegments",
          "xray:PutTelemetryRecords",
        ],
        Resource = "*"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "msk_open_monitoring_attachment" {
  role       = aws_iam_role.msk_role.name
  policy_arn = aws_iam_policy.msk_open_monitoring_policy.arn
}

# S3 bucket for storing logs
resource "aws_s3_bucket" "msk_logs_bucket" {
  bucket = "msk-logs-bucket"
  acl    = "private"
}

# Kinesis Firehose delivery stream to S3
resource "aws_kinesis_firehose_delivery_stream" "logs_to_s3" {
  name        = "msk-logs-to-s3"

  destination = "extended_s3"

  extended_s3_configuration {
    role_arn   = aws_iam_role.msk_role.arn
    bucket_arn = aws_s3_bucket.msk_logs_bucket.arn

    buffer_size = 10
    buffer_interval = 300

    cloudwatch_logging_options {
      enabled = true
      log_group_name = aws_cloudwatch_log_group.msk_log_group.name
      log_stream_name = "firehose"
    }
  }
}

# CloudWatch Log Group
resource "aws_cloudwatch_log_group" "msk_log_group" {
  name = "/aws/msk/cluster"
}

# MSK Cluster
resource "aws_msk_cluster" "msk_cluster" {
  cluster_name           = "msk-cluster"
  kafka_version          = "2.8.0"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type   = "kafka.m5.large"
    ebs_volume_size = 1000
    client_subnets  = [aws_subnet.public_a.id, aws_subnet.public_b.id]

    security_groups = [aws_security_group.msk.id]
  }

  encryption_info {
    encryption_in_transit {
      client_broker = "TLS"
    }
    encryption_at_rest {
      data_volume_kms_key_arn = aws_kms_key.msk_encryption_key.arn
    }
  }

  open_monitoring {
    prometheus {
      jmx_exporter {
        enabled_in_broker = true
        node_port = 9101
      }
    }
  }

  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled = true
        log_group_name = aws_cloudwatch_log_group.msk_log_group.name
      }
    }
  }
}

# Subnets for MSK
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "public_a" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.1.0/24"
}

resource "aws_subnet" "public_b" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.2.0/24"
}

# Security Group for MSK
resource "aws_security_group" "msk" {
  vpc_id = aws_vpc.main.id

  ingress {
    from_port   = 9092
    to_port     = 9092
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

