    "database.user"             = "dbuser",
    "database.password"         = "dbpassword",
    "database.dbname"           = "mydb",
    "database.encrypt"          = "true",
    "database.history.kafka.bootstrap.servers" = "my-msk-endpoint:9092",
    "database.history.kafka.topic"              = "dbhistory",
    "key.converter"                           = "org.apache.kafka.connect.json.JsonConverter",
    "value.converter"                         = "org.apache.kafka.connect.json.JsonConverter",
    "custom.plugin.class"                     = "io.debezium.connector.mssql.MyCustomPlugin",
    "configuration.provider.class"            = "io.debezium.config.ConfigurationProviderFile"
  })

  worker_group = "default"

  depends_on = [
    aws_msk_connect_custom_plugin.example
  ]
}

data "aws_vpc" "default" {
  default = true
}

data "aws_subnets" "default" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default.id]
  }
}

resource "aws_security_group" "example_msck" {
  name_prefix = "msk-connect-"
  vpc_id      = data.aws_vpc.default.id

  ingress {
    protocol    = "tcp"
    from_port   = 9092
    to_port     = 9092
    cidr_blocks = [aws_security_group.example.id]
  }

  egress {
    protocol    = "-1"
    from_port   = 0
    to_port     = 0
    cidr_blocks = ["0.0.0.0/0"]
  }
}
```

**Explanation:**

- **MSK Cluster**: Configures a managed MSK cluster with 3 broker nodes in `us-east-1`.
- **Security Group**: Sets up security groups to allow Kafka traffic.
- **MSK Connect**: Configures an MSK Connect cluster, a custom plugin (`debezium.zip`), and a connector using the custom plugin.
- **Networking**: Sets up a default VPC and subnets for security group configurations.

Ensure that the `debezium.zip` file is available in the working directory when executing Terraform commands. Adjust network configurations like security groups based on your actual requirements for production environments.

