To create an Aurora PostgreSQL cluster using Terraform with AWS, we need to define several resources such as a VPC, subnets, security groups, and the database cluster itself. Below is a step-by-step setup using AWS as the cloud provider. Note that you'll need to adjust variables like region, instance types, and subnet CIDRs based on your specific use case and AWS setup.

```hcl
provider "aws" {
  region = "us-west-2" # Change the region as needed
}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  enable_dns_ipv6 = true
  tags = {
    Name = "my_vpc"
  }
}

resource "aws_subnet" "main" {
  count = 3 # We'll create 3 subnets in different availability zones
  vpc_id = aws_vpc.main.id
  cidr_block = "10.0.${count.index}.0/24"
  availability_zone = "us-west-2${["a", "b", "c"][count.index]}" # adjust as needed
  map_public_ip_on_launch = true

  tags = {
    Name = "my_subnet_${count.index}"
  }
}

resource "aws_security_group" "db" {
  name        = "db-security-group"
  description = "Allow all inbound traffic to the database"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_rds_cluster" "aurora_db" {
  cluster_identifier      = "aurora-cluster-demo"
  engine                  = "aurora-postgresql"
  engine_version          = "13.4"
  database_name           = "mydb"
  master_username         = "admin"
  master_password         = "mypassword" # Change this to a secure password or use AWS Secrets Manager
  skip_final_snapshot     = true
  db_subnet_group_name    = aws_db_subnet_group.aurora_db_subnet_group.name
  vpc_security_group_ids  = [aws_security_group.db.id]

  tags = {
    Name = "aurora-postgresql-cluster"
  }
}

resource "aws_db_subnet_group" "aurora_db_subnet_group" {
  name       = "my-db-subnet-group"
  subnet_ids = aws_subnet.main[*].id

  tags = {
    Name = "my-db-subnet-group"
  }
}

resource "aws_rds_cluster_instance" "cluster_instances" {
  count = 2 # Desired number of Aurora replicas

  identifier            = "aurora-cluster-instance-${count.index}"
  cluster_identifier    = aws_rds_cluster.aurora_db.id
  instance_class        = "db.r5.large" # Adjust instance type as needed
  engine                = "aurora-postgresql"
  db_subnet_group_name  = aws_db_subnet_group.aurora_db_subnet_group.name

  tags = {
    Name = "aurora-instance-${count.index}"
  }
}
```

**Key Points:**
- The configuration deploys a VPC, three subnets, and an Aurora PostgreSQL cluster.
- A security group is set up to allow inbound connections on port 5432.
- The RDS cluster instance is preceded by two Aurora replicas.
- Adjust parameters like credentials and subnet configurations accordingly. Ensure sensitive information such as passwords are managed securely, e.g., using AWS Secrets Manager.

This setup is illustrative and may require further customization to fit specific security, scalability, and configuration requirements.

