To create an AWS Neptune cluster with two subnets, we need to perform the following steps:

1. **Create a VPC**: The subnets will be a part of this VPC.
2. **Create two Subnets**: These will reside within the VPC and be configured for the Neptune cluster.
3. **Create a Neptune Cluster**: Define the Neptune cluster to make use of the created subnets.

Here's the Terraform configuration in HCL format:

```hcl
provider "aws" {
  region = "us-west-2"
}

resource "aws_vpc" "neptune_vpc" {
  cidr_block = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "neptune_vpc"
  }
}

resource "aws_subnet" "neptune_subnet_1" {
  vpc_id            = aws_vpc.neptune_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-west-2a"

  tags = {
    Name = "neptune_subnet_1"
  }
}

resource "aws_subnet" "neptune_subnet_2" {
  vpc_id            = aws_vpc.neptune_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-west-2b"

  tags = {
    Name = "neptune_subnet_2"
  }
}

resource "aws_db_subnet_group" "neptune_subnet_group" {
  name       = "neptune-subnet-group"
  subnet_ids = [aws_subnet.neptune_subnet_1.id, aws_subnet.neptune_subnet_2.id]

  tags = {
    Name = "NeptuneSubnetGroup"
  }
}

resource "aws_db_instance" "neptune_cluster" {
  allocated_storage    = 100
  engine               = "neptune"
  instance_class       = "db.r5.large"
  db_subnet_group_name = aws_db_subnet_group.neptune_subnet_group.name
  vpc_security_group_ids = [aws_security_group.neptune_sg.id]
  iam_database_authentication_enabled = true
  skip_final_snapshot = true

  tags = {
    Name = "NeptuneCluster"
  }
}

resource "aws_security_group" "neptune_sg" {
  name        = "neptune_sg"
  description = "Security group for Neptune cluster"
  vpc_id      = aws_vpc.neptune_vpc.id

  ingress {
    from_port   = 8182
    to_port     = 8182
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "NeptuneSecurityGroup"
  }
}
```

This setup will create a VPC with two subnets, a security group, a subnet group for Neptune, and an instance of AWS Neptune using the configured subnets. Adjust the configurations, such as CIDR blocks or instance types, as needed to fit your specific requirements.

