response:
To create an AWS Redshift cluster with endpoint access from two subnets using Terraform, we need to consider several components: the VPC, subnets, security groups, the Redshift cluster itself, and relevant network configurations.

Here's a step-by-step breakdown of the requirements:

1. **VPC Setup**: We need a VPC to create our subnets and other networking resources.

2. **Subnets**: Ensure we have two subnets, possibly in different availability zones for high availability.

3. **Security Group**: Define a security group that will allow access to the Redshift cluster.

4. **Redshift Cluster**: Configure the Redshift cluster to be accessible from these subnets.

Let's translate these into Terraform configurations:

```hcl
provider "aws" {
  region = "us-west-2"
}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "main-vpc"
  }
}

resource "aws_subnet" "subnet_1" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-west-2a"

  tags = {
    Name = "subnet-1"
  }
}

resource "aws_subnet" "subnet_2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-west-2b"

  tags = {
    Name = "subnet-2"
  }
}

resource "aws_redshift_subnet_group" "redshift_subnet_group" {
  name       = "redshift-subnet-group"
  subnet_ids = [aws_subnet.subnet_1.id, aws_subnet.subnet_2.id]

  tags = {
    Name = "redshift-subnet-group"
  }
}

resource "aws_security_group" "redshift_sg" {
  name        = "redshift-security-group"
  description = "Allow Redshift access"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "redshift-sg"
  }
}

resource "aws_redshift_cluster" "redshift_cluster" {
  cluster_identifier      = "my-redshift-cluster"
  database_name           = "mydb"
  master_username         = "admin"
  master_password         = "SuperSecretPassword"  # Use a secrets management solution in production
  node_type               = "dc2.large"
  cluster_type            = "multi-node"
  number_of_nodes         = 2
  publicly_accessible     = true
  skip_final_snapshot     = true
  cluster_subnet_group_name = aws_redshift_subnet_group.redshift_subnet_group.name
  vpc_security_group_ids  = [aws_security_group.redshift_sg.id]
  preferred_maintenance_window = "mon:01:00-mon:03:00"

  tags = {
    Name = "MyRedshiftCluster"
  }
}
```

### Key Points:
- **VPC and Subnets**: The configuration creates a VPC and two subnets in different availability zones.
- **Redshift Subnet Group**: This allows the Redshift cluster to be associated with the specified subnets.
- **Security Group**: Allowing inbound access to the Redshift default port (5439) for connections. For production, consider restricting access to specific IP addresses.
- **Redshift Cluster**: Configured with the specified settings and connected to the subnet group and security group.

Ensure to replace sensitive values like `master_password` with a secure mechanism for handling secrets.

