   - Enable static website hosting on the bucket.

2. **Upload the `index.html` File**:
   - Utilize `aws_s3_bucket_object` to upload the `index.html` file to the bucket.

3. **Set up Bucket Policy for Public Access**:
   - Define a bucket policy using `aws_s3_bucket_policy` to allow public read access to the bucket's objects.

Here's the complete Terraform configuration to achieve the above requirements:

```hcl
provider "aws" {
  region = "us-east-1"  # Specify the AWS region
}

resource "aws_s3_bucket" "static_site" {
  bucket = "my-static-website-bucket"  # Ensure this is globally unique
  acl    = "public-read"

  website {
    index_document = "index.html"
  }

  tags = {
    Name = "Static Website Bucket"
  }
}

resource "aws_s3_bucket_policy" "policy" {
  bucket = aws_s3_bucket.static_site.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action    = ["s3:GetObject"]
        Effect    = "Allow"
        Resource  = "${aws_s3_bucket.static_site.arn}/*"
        Principal = "*"
      }
    ]
  })
}

resource "aws_s3_bucket_object" "index" {
  bucket = aws_s3_bucket.static_site.bucket
  key    = "index.html"
  source = "path/to/local/index.html"  # Specify the path to your local index.html file
  acl    = "public-read"
  content_type = "text/html"
}

```

