  }
}

resource "aws_s3_bucket" "my_bucket" {
  bucket = "my-bucket"
  acl    = "private"

  versioning {
    enabled = true
  }

  logging {
    target_bucket = aws_s3_bucket.my_log_bucket.id
    target_prefix = "log/"
  }

  lifecycle {
    prevent_destroy = true
  }
}

resource "aws_s3_bucket_policy" "allow_bucket_logging" {
  bucket = aws_s3_bucket.my_log_bucket.id

  policy = data.aws_iam_policy_document.allow_bucket_logging.json
}

data "aws_iam_policy_document" "allow_bucket_logging" {
  statement {
    actions = [
      "s3:PutObject",
    ]

    resources = [
      "${aws_s3_bucket.my_log_bucket.arn}/log/*",
    ]

    principals {
      type        = "Service"
      identifiers = ["logging.s3.amazonaws.com"]
    }
  }
}
```

### Explanation:
- **`aws_s3_bucket.my_log_bucket`**: This resource creates the bucket where logs will be stored. It has versioning enabled and a lifecycle policy that prevents accidental deletion.
- **`aws_s3_bucket.my_bucket`**: This resource creates the bucket whose access logs will be stored. It includes a logging configuration pointing to `my_log_bucket`.
- **`aws_s3_bucket_policy.allow_bucket_logging`**: This policy grants permission for the `logging.s3.amazonaws.com` service to write logs into `my_log_bucket`.

Make sure to replace `"my-bucket"` and `"my-log-bucket"` with unique bucket names that comply with S3 naming rules.

