To set up an AWS infrastructure for an autograder using AWS CodeBuild, we need to consider the following requirements:

1. **GitHub Source Connection**: CodeBuild will need access to the GitHub repository where students' code is stored.
2. **CodeBuild Project**: Define the CodeBuild project to build and test code, specifying the build environment and necessary build commands.
3. **IAM Roles and Policies**: Set up IAM roles and policies to give CodeBuild the necessary permissions to access S3 for storage of results and any other required AWS services.
4. **S3 Bucket**: Use S3 to store the results of the grading process.

Here's the Terraform configuration delivering these requirements:

```hcl
provider "aws" {
  region = "us-west-2"
}

# S3 Bucket to store build results
resource "aws_s3_bucket" "build_results" {
  bucket = "cs-class-autograder-results"
  acl    = "private"

  tags = {
    Name = "CS-Class Autograder Results"
  }
}

# IAM role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "codebuild-cs-autograder-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy to allow access to S3
resource "aws_iam_policy" "codebuild_s3_policy" {
  name        = "codebuild-s3-access-policy"
  description = "Allow CodeBuild to access S3 bucket"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Effect = "Allow"
        Resource = [
          "${aws_s3_bucket.build_results.arn}",
          "${aws_s3_bucket.build_results.arn}/*"
        ]
      }
    ]
  })
}

# Attach the policy to the role
resource "aws_iam_role_policy_attachment" "codebuild_s3_attachment" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = aws_iam_policy.codebuild_s3_policy.arn
}

# CodeBuild project configuration
resource "aws_codebuild_project" "autograder" {
  name          = "cs-autograder"
  description   = "Automated grading for CS class"
  build_timeout = "5"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:6.0"
    type                        = "LINUX_CONTAINER"
    environment_variable {
      name  = "GITHUB_REPO"
      value = "https://github.com/YOUR_GITHUB_USERNAME/YOUR_REPOSITORY_NAME.git"
    }
    environment_variable {
      name  = "S3_BUCKET"
      value = aws_s3_bucket.build_results.bucket
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/YOUR_GITHUB_USERNAME/YOUR_REPOSITORY_NAME.git"
    git_clone_depth = 1
  }

  source_version = "main"

  vpc_config {
    # Configure VPC if required, otherwise remove
    # security_group_ids = [aws_security_group.sg.id]
    # subnets            = [aws_subnet.subnet_public1.id, aws_subnet.subnet_private1.id]
  }

  # IAM permissions to retrieve code and push artifacts
  logs_config {
    cloudwatch_logs {
      group_name = "codebuild-autograder-logs"
      stream_name = "codebuild-autograder-logs-stream"
    }
  }
}

```

### Notes:
- Replace `"YOUR_GITHUB_USERNAME/YOUR_REPOSITORY_NAME.git"` with the GitHub repository details.
- The IAM role and its associated policies allow CodeBuild access to the specified S3 bucket for result storage.
- Adjust AWS region and resource identifiers such as subnets and security groups according to your AWS setup.
- This configuration does not deploy any resources related to VPC, but hooks for its configuration are included. Adjust as needed if deployment occurs within a VPC.

