    location = aws_s3_bucket.autograder_s3.bucket
  }

  tags = {
    Name = "autograder_codebuild"
  }
}

resource "aws_iam_role" "autograder_codebuild" {
  name = "autograder_codebuild_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      },
    ]
  })
}

resource "aws_iam_role_policy" "autograder_codebuild_policy" {
  name = "autograder_codebuild_policy"
  role = aws_iam_role.autograder_codebuild.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:ListBucket"
        ]
        Effect   = "Allow"
        Resource = [
          "${aws_s3_bucket.autograder_s3.arn}",
          "${aws_s3_bucket.autograder_s3.arn}/*"
        ]
      },
      {
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Effect = "Allow"
        Resource = "arn:aws:logs:*:*:*"
      }
    ]
  })
}
```

### Key Considerations:
- **S3 For Code Publishing**: Student code is fetched from a GitHub repo and stored in an S3 bucket.
- **Security via Subnets and Security Groups**: The CodeBuild is restricted to a private subnet, and a security group blocks all non-essential traffic.
- **IAM Role**: Provides permissions for CodeBuild to access required services like S3 and CloudLogs.
- **Replace placeholders**: Adjust IAM policies, GitHub repo links, and S3 bucket names according to your organization needs.

