response:
To achieve this, we need to configure the following components:

1. **AWS EC2 Instance**: This will represent the compute resource.
2. **AWS Backup**: This service will be used to create a daily backup of the EC2 instance.
3. **AWS Backup Plan and Vault**: These are required to define how the backup happens.
4. **AWS Backup Selection**: This targets which resources to be backed up.
5. **IAM Role and Policy**: Necessary for granting AWS Backup service the permissions required to access the EC2 instance.

Here is the Terraform configuration:

```hcl
provider "aws" {
  region = "us-west-2"
}

resource "aws_iam_role" "backup_role" {
  name               = "ec2-backup-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "backup.amazonaws.com"
      }
    }]
  })
}

resource "aws_iam_policy" "backup_policy" {
  name   = "ec2-backup-policy"
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "ec2:CreateSnapshot",
          "ec2:Describe*",
        ],
        Resource = "*"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "backup_role_policy_attachment" {
  policy_arn = aws_iam_policy.backup_policy.arn
  role       = aws_iam_role.backup_role.name
}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "main" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.1.0/24"
}

resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id
}

resource "aws_route_table" "main" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }
}

resource "aws_route_table_association" "main" {
  subnet_id      = aws_subnet.main.id
  route_table_id = aws_route_table.main.id
}

resource "aws_security_group" "allow_ssh" {
  vpc_id = aws_vpc.main.id

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_key_pair" "deployer_key" {
  key_name   = "deployer-key"
  public_key = file("~/.ssh/id_rsa.pub")
}

resource "aws_instance" "example" {
  ami                    = "ami-0e34e7b9ca0ace12d" # Update this AMI ID accordingly
  instance_type          = "t2.micro"
  key_name               = aws_key_pair.deployer_key.key_name
  subnet_id              = aws_subnet.main.id
  vpc_security_group_ids = [aws_security_group.allow_ssh.id]

  tags = {
    Name = "ExampleInstance"
  }
}

resource "aws_backup_vault" "backup_vault" {
  name = "ec2-backup-vault"
}

resource "aws_backup_selection" "ec2_selection" {
  iam_role_arn = aws_iam_role.backup_role.arn
  name         = "ec2-backup-selection"
  plan_id      = aws_backup_plan.daily_backup_plan.id

  resources = [
    aws_instance.example.arn,
  ]
}

resource "aws_backup_plan" "daily_backup_plan" {
  name = "daily-backup-plan"

  rule {
    rule_name         = "daily-backup"
    target_vault_name = aws_backup_vault.backup_vault.name
    schedule          = "cron(0 0 * * ? *)"
    start_window      = 120
    completion_window = 360
    retention {
      count = 30
      unit  = "days"
    }
  }
}
```

### Explanation:

1. **AWS Provider**: Configured for the US West (Oregon) region.
2. **IAM Role and Policy**: Created a role and policy that allows AWS Backup to create snapshots of the EC2 instance.
3. **AWS VPC, Subnet**: Setup basic networking components.
4. **AWS Security Group**: Allows SSH access to the EC2 instance.
5. **AWS Key Pair**: Allows SSH access from your local machine (update the public key path).
6. **AWS EC2 Instance**: Configures the EC2 instance with a given AMI ID, networking settings, and attaches the security group and key pair.
7. **AWS Backup Components**: Configures a backup vault, backup selection, and backup plan to perform daily backups at midnight. The selected resource is the EC2 instance.

**Note**: Ensure you update the AMI ID (`ami-0e34e7b9ca0ace12d`) to match an appropriate AMI in your region. Also, update the SSH public key path `~/.ssh/id_rsa.pub` if necessary.

