provider "aws" {
  region = "us-east-1"
}

# AWS Key Pair for EC2 Instance
resource "aws_key_pair" "example_key" {
  key_name   = "example-key"
  public_key = "ssh-rsa AAAAB3NzaC1yc2EAAAADAQABAAABAQC..."
}

# AWS Security Group for EC2
resource "aws_security_group" "example_sg" {
  name        = "example-sg"
  description = "Allow SSH inbound traffic"

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# AWS EC2 Instance
resource "aws_instance" "example_instance" {
  ami           = "ami-0c55b159cbfafe1f0"  # Example AMI, ensure availability in your region
  instance_type = "t2.micro"
  key_name      = aws_key_pair.example_key.key_name
  security_groups = [aws_security_group.example_sg.name]

  tags = {
    Name = "ExampleInstance"
  }
}

# AWS Backup Vault
resource "aws_backup_vault" "example_vault" {
  name = "example-vault"
}

# AWS Backup Plan
resource "aws_backup_plan" "example_plan" {
  name = "example-plan"

  rule {
    rule_name         = "DailyBackup"
    target_vault_name = aws_backup_vault.example_vault.name

    schedule = "cron(0 0 * * ? *)"

    lifecycle {
      cold_storage_after = 30
      delete_after       = 90
    }
  }
}

# AWS Backup Selection for EC2 Resource
resource "aws_backup_selection" "example_selection" {
  iam_role_arn = "arn:aws:iam::123456789012:role/service-role/AWSBackupDefaultServiceRole"
  plan_id      = aws_backup_plan.example_plan.id

  selection_tags = {
    "Backup" = "Daily"
  }

  resources = [
    "arn:aws:ec2:us-east-1:123456789012:instance/${aws_instance.example_instance.id}"
  ]
}

resource "aws_backup_plan_resource_selection" "example_plan_resource_selection" {
