To achieve your request, we'll configure the following AWS resources using Terraform:

1. **AWS Lambda Function**: This function will execute the desired code.
2. **AWS EventBridge Event Rule**: This rule will schedule the Lambda function to be invoked daily at 7 UTC.
3. **AWS EventBridge Event Target**: This connects the scheduled rule to the Lambda function.
4. **AWS Lambda Permission**: This grants the EventBridge service permission to invoke the Lambda function.

Here's the step-by-step Terraform configuration in HashiCorp Configuration Language (HCL):

```hcl
provider "aws" {
  region = "us-east-1" # Change this to your desired AWS region
}

resource "aws_iam_role" "lambda_role" {
  name = "lambda_execution_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "lambda.amazonaws.com"
        },
        Effect = "Allow",
        Sid = ""
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lambda_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

resource "aws_lambda_function" "example_lambda" {
  function_name = "example_function"

  s3_bucket = "your-lambda-code-bucket" # Replace with your S3 bucket
  s3_key    = "your-lambda-code.zip"    # Replace with your Lambda deployment package

  handler = "index.handler"
  role    = aws_iam_role.lambda_role.arn

  runtime = "nodejs14.x" # Or any other runtime
}

resource "aws_cloudwatch_event_rule" "daily_event" {
  name                = "daily_event"
  schedule_expression = "cron(0 7 * * ? *)"
}

resource "aws_cloudwatch_event_target" "lambda_target" {
  rule      = aws_cloudwatch_event_rule.daily_event.name
  target_id = "example_lambda"
  arn       = aws_lambda_function.example_lambda.arn
}

resource "aws_lambda_permission" "allow_event_bridge" {
  statement_id  = "AllowExecutionFromEventBridge"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.example_lambda.function_name
  principal     = "events.amazonaws.com"
  source_arn    = aws_cloudwatch_event_rule.daily_event.arn
}
```

**Notes**:

- Change the `s3_bucket` and `s3_key` in the `aws_lambda_function` resource to point to your Lambda deployment package stored in an S3 bucket.
- The `runtime` can be adjusted to match your Lambda's required runtime environment.
- Ensure the AWS region is set to where you want to deploy these resources.

