}

response:
To set up a global video streaming infrastructure on AWS using Terraform, we'll go through the following components and their interdependencies step-by-step. We'll create a structured configuration for the infrastructure:

1. **AWS S3 Bucket**: Storage for video content
2. **AWS S3 Bucket Policy**: Set permissions to allow CloudFront to access the content
3. **AWS CloudFront Origin Access Control**: Control access to the S3 bucket
4. **AWS CloudFront Distribution**: Set up a distribution to cache and deliver content globally
5. **AWS Route53 Zone**: DNS management for the domain
6. **AWS Route53 Record**: Map the domain to the CloudFront distribution

Here's the Terraform configuration:

```hcl
provider "aws" {
  region = "us-east-1"
}

resource "aws_s3_bucket" "video_content" {
  bucket = "my-video-content-bucket"
  acl    = "private"
}

resource "aws_s3_bucket_policy" "bucket_policy" {
  bucket = aws_s3_bucket.video_content.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect    = "Allow"
        Principal = {
          Service = "cloudfront.amazonaws.com"
        }
        Action   = "s3:GetObject"
        Resource = "${aws_s3_bucket.video_content.arn}/*"
        Condition = {
          StringEquals = {
            "AWS:SourceArn" = aws_cloudfront_origin_access_control.default.OriginAccessControlOriginArn
          }
        }
      }
    ]
  })
}

resource "aws_cloudfront_origin_access_control" "default" {
  name                          = "s3-access-control"
  description                   = "CloudFront Origin Access Control for S3"
  origin_access_control_origin_type = "s3"
  signing_behavior              = "always"
  signing_protocol              = "sigv4"
}

resource "aws_cloudfront_distribution" "video_distribution" {
  origin {
    domain_name = aws_s3_bucket.video_content.bucket_regional_domain_name
    origin_id   = "S3-video-content"

    s3_origin_config {
      origin_access_control_id = aws_cloudfront_origin_access_control.default.id
    }
  }

  enabled             = true
  is_ipv6_enabled     = true
  comment             = "Global video content distribution"
  default_cache_behavior {
    allowed_methods  = ["GET", "HEAD"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = "S3-video-content"

    forwarded_values {
      query_string = false
      cookies {
        forward = "none"
      }
    }

    viewer_protocol_policy = "redirect-to-https"
    min_ttl                = 0
    default_ttl            = 3600
    max_ttl                = 86400
  }

  price_class = "PriceClass_All"
  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  viewer_certificate {
    cloudfront_default_certificate = true
  }

  default_root_object = "index.html"
}

resource "aws_route53_zone" "example" {
  name = "example.com"
}

resource "aws_route53_record" "cloudfront" {
  zone_id = aws_route53_zone.example.zone_id
  name    = "videos.example.com"
  type    = "A"

  alias {
    name                   = aws_cloudfront_distribution.video_distribution.domain_name
    zone_id                = aws_cloudfront_distribution.video_distribution.hosted_zone_id
    evaluate_target_health = false
  }
}
```

This configuration includes:
- An S3 bucket to store video files.
- A bucket policy to restrict access to CloudFront only.
- Origin access control to secure access from CloudFront to the S3 bucket.
- A CloudFront distribution to deliver content globally with a performance-enhancing setup.
- A Route53 zone and record to map the domain to the CloudFront distribution for easy access.

