response:
To create the infrastructure for a video streaming site with load balancing using AWS, we need to consider the following components:

1. **VPC**: A Virtual Private Cloud to host our infrastructure.
2. **Subnets**: Public and private subnets for load balancers and EC2 instances.
3. **Internet Gateway**: To connect the VPC to the internet.
4. **Route Tables**: To route traffic from the subnets to the internet.
5. **Security Groups**: To control traffic to and from EC2 instances.
6. **EC2 Instances**: Servers to handle the traffic for the video streaming site.
7. **Load Balancer**: To distribute traffic across the EC2 instances.

Here's the Terraform configuration for the described infrastructure:

```hcl
provider "aws" {
  region = "us-east-1"
}

# VPC
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags = {
    Name = "main-vpc"
  }
}

# Internet Gateway
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id
  tags = {
    Name = "main-igw"
  }
}

# Subnets
resource "aws_subnet" "public_subnet" {
  count                   = 2
  vpc_id                  = aws_vpc.main.id
  cidr_block              = count.index == 0 ? "10.0.1.0/24" : "10.0.2.0/24"
  map_public_ip_on_launch = true
  availability_zone       = count.index == 0 ? "us-east-1a" : "us-east-1b"
  tags = {
    Name = "public-subnet-${count.index}"
  }
}

resource "aws_subnet" "private_subnet" {
  count             = 2
  vpc_id            = aws_vpc.main.id
  cidr_block        = count.index == 0 ? "10.0.3.0/24" : "10.0.4.0/24"
  availability_zone = count.index == 0 ? "us-east-1a" : "us-east-1b"
  tags = {
    Name = "private-subnet-${count.index}"
  }
}

# Route Table and Association
resource "aws_route_table" "public_route_table" {
  vpc_id = aws_vpc.main.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }
  tags = {
    Name = "public-route-table"
  }
}

resource "aws_route_table_association" "public_route_table_association" {
  count          = length(aws_subnet.public_subnet)
  subnet_id      = aws_subnet.public_subnet[count.index].id
  route_table_id = aws_route_table.public_route_table.id
}

# Security Group for EC2 Instances
resource "aws_security_group" "ec2_sg" {
  name        = "ec2-sg"
  description = "Security group for EC2 instances"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Load Balancer
resource "aws_lb" "alb" {
  name               = "video-streaming-alb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb_sg.id]
  subnets            = aws_subnet.public_subnet[*].id

  tags = {
    Name = "video-streaming-alb"
  }
}

resource "aws_security_group" "alb_sg" {
  name        = "alb-sg"
  description = "Security group for ALB"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Target Group
resource "aws_lb_target_group" "tg" {
  name     = "video-streaming-tg"
  port     = 80
  protocol = "HTTP"
  vpc_id   = aws_vpc.main.id
}

# Listener
resource "aws_lb_listener" "listener" {
  load_balancer_arn = aws_lb.alb.arn
  port              = 80
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.tg.arn
  }
}

# EC2 Instance
resource "aws_instance" "web_server" {
  count                       = 2
  ami                         = "ami-0c55b159cbfafe1f0" # Example AMI ID
  instance_type               = "t2.micro"
  subnet_id                   = aws_subnet.private_subnet[count.index % 2].id
  vpc_security_group_ids      = [aws_security_group.ec2_sg.id]
  associate_public_ip_address = false

  tags = {
    Name = "web-server-${count.index}"
  }
}

# Target Group Attachment
resource "aws_lb_target_group_attachment" "tg_attachment" {
  count             = 2
  target_group_arn  = aws_lb_target_group.tg.arn
  target_id         = aws_instance.web_server[count.index].id
  port              = 80
}
```

This configuration sets up a basic infrastructure for a video streaming site with an AWS Application Load Balancer (ALB) distributing traffic across two EC2 instances. Adjust the AMI ID, instance types, and CIDR blocks as needed for your specific requirements.

