response:
To fulfill this request, we need to create a Terraform configuration that sets up the following infrastructure elements in AWS:

1. A VPC with a CIDR block of `10.0.0.0/16`.
2. Three subnets within the VPC with specified CIDR blocks.
3. A security group within the VPC.
4. An ingress rule to allow traffic from within the VPC on port 80.
5. An egress rule to allow traffic to any IP address on port 80.
6. An application load balancer (ALB) with a security group and subnets.
7. A target group for the ALB with HTTP protocol on port 80.
8. An ALB listener that forwards traffic from the load balancer to the target group.
9. A target group attachment for an EC2 instance.
10. A Route 53 hosted zone for `test-video-stream.com`.
11. Two alias records for domain and subdomain pointing to the ALB DNS name.

Here's the complete Terraform configuration:

```hcl
provider "aws" {
  region = "us-west-2"
}

module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"
  version = "3.19.0"

  name = "test-vpc"
  cidr = "10.0.0.0/16"

  azs             = ["us-west-2a", "us-west-2b", "us-west-2c"]
  private_subnets = ["10.0.4.0/24", "10.0.5.0/24", "10.0.6.0/24"]
}

resource "aws_security_group" "alb_sg" {
  name_prefix = "alb-sg-"
  vpc_id      = module.vpc.vpc_id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = [module.vpc.vpc_cidr_block]
  }

  egress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_lb" "test_lb" {
  name               = "test-lb"
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb_sg.id]
  subnets            = module.vpc.private_subnets
}

resource "aws_lb_target_group" "test_tg" {
  name     = "test-tg"
  port     = 80
  protocol = "HTTP"
  vpc_id   = module.vpc.vpc_id
}

resource "aws_lb_listener" "test_listener" {
  load_balancer_arn = aws_lb.test_lb.arn
  port              = 80
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.test_tg.arn
  }
}

resource "aws_launch_configuration" "test_lc" {
  name_prefix   = "test-lc-"
  image_id      = data.aws_ami.ubuntu.id
  instance_type = "t2.micro"

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_autoscaling_group" "test_asg" {
  launch_configuration = aws_launch_configuration.test_lc.id
  min_size             = 1
  max_size             = 1
  vpc_zone_identifier  = module.vpc.private_subnets
  target_group_arns    = [aws_lb_target_group.test_tg.arn]
}

resource "aws_lb_target_group_attachment" "test_attachment" {
  target_group_arn = aws_lb_target_group.test_tg.arn
  target_id        = aws_autoscaling_group.test_asg.instances.0.id
  port             = 80
}

data "aws_ami" "ubuntu" {
  most_recent = true
  filter {
    name   = "name"
    values = ["ubuntu/images/hvm-ssd/ubuntu-focal-20.04-amd64-server-*"]
  }
  filter {
    name   = "virtualization-type"
    values = ["hvm"]
  }
  owners = ["099720109477"] # Canonical
}

resource "aws_route53_zone" "test_zone" {
  name = "test-video-stream.com"
}

resource "aws_route53_record" "lb_alias" {
  zone_id = aws_route53_zone.test_zone.zone_id
  name    = "lb.test-video-stream.com"
  type    = "A"

  alias {
    name                   = aws_lb.test_lb.dns_name
    zone_id                = aws_lb.test_lb.zone_id
    evaluate_target_health = true
  }
}

resource "aws_route53_record" "domain_alias" {
  zone_id = aws_route53_zone.test_zone.zone_id
  name    = "test-video-stream.com"
  type    = "A"

  alias {
    name                   = aws_lb.test_lb.dns_name
    zone_id                = aws_lb.test_lb.zone_id
    evaluate_target_health = true
  }
}
```

This configuration sets up the entire infrastructure as specified in the request. Adjust the AWS region and availability zones as necessary for your setup.

