  cidr_ipv4       = "0.0.0.0/0"
  security_group_id = aws_security_group.db-sg.id
}

resource "aws_db_parameter_group" "postgre-param-group" {
  name   = "pgparamgrp15"
  family = "postgres15"

  parameter {
    name  = "password_encryption"
    value = "scram-sha-256"
  }

  parameter {
    name  = "rds.force_ssl"
    value = "0"
  }

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_kms_key" "rds-key" {
  description             = "kmsrds"
  deletion_window_in_days = 14
}

resource "aws_db_instance" "postgres" {
  identifier                      = "pg"
  skip_final_snapshot             = true
  allocated_storage               = 50
  backup_retention_period         = 7
  db_subnet_group_name            = aws_db_subnet_group.db-subnet-group.id
  parameter_group_name            = aws_db_parameter_group.postgre-param-group.name
  enabled_cloudwatch_logs_exports = ["postgresql", "upgrade"]
  engine                          = "postgres"
  engine_version                  = "15"
  instance_class                  = "db.t3.micro"
  db_name                         = "postgres" # Initial database name
  username                        = "myusername"
  password                        = "mypassword"
  vpc_security_group_ids          = [aws_security_group.db-sg.id]
  # Other security settings
  publicly_accessible             = true
  multi_az                        = true
  storage_encrypted               = true
  kms_key_id                      = aws_kms_key.rds-key.arn
  # Default daily backup window
  # https://docs.aws.amazon.com/AmazonRDS/latest/UserGuide/USER_WorkingWithAutomatedBackups.html#USER_WorkingWithAutomatedBackups.BackupWindow
}

response:
To provision a secure PostgreSQL database instance in AWS using Terraform, we need to set up the following components:

1. **VPC and Subnets**: Ensure the PostgreSQL instance is inside a specified VPC and subnets.

2. **Security Group**: Define a security group to control access to the RDS instance.

3. **KMS Key**: Create or use an existing KMS key for encrypting the database.

4. **DB Parameter Group**: Define a custom parameter group for PostgreSQL-specific settings.

5. **RDS Instance**: Deploy the PostgreSQL database, ensuring specifications for engine version, storage, multi-AZ deployment, and encryption.

Here is the complete Terraform configuration in HCL format:

```hcl
provider "aws" {
  region = "us-west-2"
}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "public_subnet" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-west-2a"
}

resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-west-2a"
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.3.0/24"
  availability_zone = "us-west-2b"
}

resource "aws_security_group" "rds_sg" {
  name        = "postgres-rds-sg"
  description = "Security group for PostgreSQL RDS"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_kms_key" "rds_kms_key" {
  description             = "KMS key for encrypting RDS instance"
  deletion_window_in_days = 10
}

resource "aws_db_parameter_group" "postgrest_parameters" {
  name        = "postgres-custom-parameters"
  family      = "postgres15"
  description = "Custom parameter group for PostgreSQL 15"

  parameter {
    name  = "max_connections"
    value = "200"
  }
}

resource "aws_db_subnet_group" "db_subnet_group" {
  name       = "postgres-subnet-group"
  subnet_ids = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id]

  tags = {
    Name = "My DB Subnet Group"
  }
}

resource "aws_rds_cluster" "postgres_cluster" {
  cluster_identifier      = "postgres-cluster"
  engine                  = "aurora-postgresql"
  engine_version          = "15.1"
  database_name           = "my_database"
  master_username         = "admin"
  master_password         = "password123"
  db_subnet_group_name    = aws_db_subnet_group.db_subnet_group.name
  vpc_security_group_ids  = [aws_security_group.rds_sg.id]
  kms_key_id              = aws_kms_key.rds_kms_key.arn
  backup_retention_period = 7
  storage_encrypted       = true
  availability_zones      = ["us-west-2a", "us-west-2b"]
}

resource "aws_rds_cluster_instance" "postgres_instance" {
  identifier         = "postgres-instance-1"
  cluster_identifier = aws_rds_cluster.postgres_cluster.id
  instance_class     = "db.r5.large"
  engine             = "aurora-postgresql"
  engine_version     = "15.1"
  skip_final_snapshot = true
  parameter_group_name = aws_db_parameter_group.postgrest_parameters.name
  storage_encrypted   = true
}

output "rds_cluster_endpoint" {
  value = aws_rds_cluster.postgres_cluster.endpoint
}
```

This configuration sets up:
- A VPC with subnets for the database instance.
- A security group allowing PostgreSQL traffic on port 5432.
- A KMS key for RDS encryption.
- A custom parameter group for PostgreSQL settings.
- An Aurora PostgreSQL cluster with your specified configurations.

