provider "aws" {
  region = "us-west-2" # Change this based on your region preference
}

# Define the VPC and subnets where your RDS instance will reside
resource "aws_vpc" "example" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "public_subnet_1" {
  vpc_id            = aws_vpc.example.id
  cidr_block        = "10.0.1.0/24"
  map_public_ip_on_launch = true
  availability_zone = "us-west-2a"
}

resource "aws_subnet" "public_subnet_2" {
  vpc_id            = aws_vpc.example.id
  cidr_block        = "10.0.2.0/24"
  map_public_ip_on_launch = true
  availability_zone = "us-west-2b"
}

# Create the RDS instance
resource "aws_db_instance" "airbyte_connector_test_db" {
  identifier           = "airbyte-test-database"
  engine               = "postgres"
  engine_version       = "15"
  instance_class       = "db.t3.medium"
  allocated_storage    = 20
  storage_type         = "gp2"
  vpc_security_group_ids = [aws_security_group.db.id]
  db_subnet_group_name = aws_db_subnet_group.example.name
  publicly_accessible  = true

  skip_final_snapshot = true
  apply_immediately   = true

  username = "dbadmin"
  password = "securepassword123" # Change this to a more secure password

  # Tags
  tags = {
    Name = "AirbyteConnectortestDB"
  }
}

# Create a DB Security Group
