  name_prefix = "db-credentials-"
}

resource "aws_secretsmanager_secret_version" "db-credentials-version" {
  secret_id     = aws_secretsmanager_secret.db-credentials.id
  secret_string = jsonencode({
    username = aws_rds_cluster.example.master_username
    password = aws_rds_cluster.example.master_password
  })
}

resource "aws_iam_role" "rds-proxy-role" {
  name = "rds-proxy-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_policy" "rds-proxy-policy" {
  name        = "rds-proxy-policy"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "secretsmanager:GetSecretValue",
        ]
        Resource = [
          "${aws_secretsmanager_secret_version.db-credentials-version.arn}",
        ]
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "attach-proxy-policy" {
  role       = aws_iam_role.rds-proxy-role.name
  policy_arn = aws_iam_policy.rds-proxy-policy.arn
}

resource "aws_db_proxy" "example" {
  name                   = "example-proxy"
  debug_logging          = false
  engine_family          = "MYSQL"
  idle_client_timeout    = 1800
  require_tls            = true
  role_arn               = aws_iam_role.rds-proxy-role.arn
  vpc_security_group_ids = [aws_security_group.rds-proxy-sg.id]
  vpc_subnet_ids         = module.vpc.private_subnets

  auth {
    auth_scheme  = "SECRETS"
    secret_arn   = aws_secretsmanager_secret.db-credentials.arn
    iam_auth     = "DISABLED"
  }
}

resource "aws_db_proxy_default_target_group" "example" {
  db_proxy_name = aws_db_proxy.example.name

  connection_pool_config {
    connection_borrow_timeout    = 120
    init_query                   = "SET x=1, y=2"
    max_connections_percent      = 100
    max_idle_connections_percent = 50
    session_pinning_filters      = ["EXCLUDE_VARIABLE_SETS"]
  }
}

resource "aws_db_proxy_target" "example" {
  db_cluster_identifier = aws_rds_cluster.example.cluster_identifier
  db_proxy_name          = aws_db_proxy.example.name
  target_group_name      = aws_db_proxy_default_target_group.example.name
}

response:
To set up an AWS RDS Aurora MySQL cluster with a proxy using Terraform, we need to consider several components including the VPC, subnets, security groups, IAM roles, RDS cluster itself, RDS Proxy, and Secrets Manager for secure credential storage. Below is the step-by-step Terraform configuration to achieve this setup. The configuration will result in an RDS Aurora MySQL cluster with an associated RDS Proxy, deployed within a custom VPC and associated security groups. We'll also use AWS Secrets Manager to store the database credentials securely.

```hcl
provider "aws" {
  region = "us-west-2"
}

locals {
  cluster_identifier = "aurora-cluster-demo"
  db_cluster_name    = "aurora-cluster-demo"
  db_instance_class  = "db.t3.medium"
  db_name            = "mydb"
  snapshot_identifier = "snapshot"
}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "main"
  }
}

resource "aws_subnet" "public" {
  count = 2

  vpc_id     = aws_vpc.main.id
  cidr_block = count.index == 0 ? "10.0.1.0/24" : "10.0.2.0/24"
  availability_zone = length(data.aws_availability_zones.available.names) > count.index ? data.aws_availability_zones.available.names[count.index] : null

  tags = {
    Name = "public-${count.index}"
  }
}

resource "aws_db_subnet_group" "main" {
  name       = "my-db-subnet-group"
  subnet_ids = aws_subnet.public[*].id

  tags = {
    Name = "My DB Subnet Group"
  }
}

resource "aws_security_group" "rds" {
  name        = "rds-security-group"
  description = "Allow inbound MySQL traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_rds_cluster" "aurora_cluster" {
  cluster_identifier      = local.db_cluster_name
  engine                  = "aurora-mysql"
  engine_version          = "5.7.12"
  database_name           = local.db_name
  master_username         = var.db_master_username
  master_password         = aws_secretsmanager_secret_version.db_secret.secret_string
  backup_retention_period = 7
  deletion_protection     = false
  skip_final_snapshot     = false
  final_snapshot_identifier = local.snapshot_identifier

  db_subnet_group_name = aws_db_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.rds.id]

  tags = {
    Name = "My Aurora Cluster"
  }
}

resource "aws_rds_cluster_instance" "aurora_instance" {
  count                       = 2
  identifier                  = format("%s-instance%d", local.db_cluster_name, count.index)
  cluster_identifier          = aws_rds_cluster.aurora_cluster.id
  instance_class              = local.db_instance_class
  engine                      = aws_rds_cluster.aurora_cluster.engine
  db_subnet_group_name        = aws_db_subnet_group.main.name
  publicly_accessible         = false
}

resource "aws_secretsmanager_secret" "db_secret" {
  name                       = "rds-cluster-db-secret"
}

resource "aws_secretsmanager_secret_version" "db_secret" {
  secret_id     = aws_secretsmanager_secret.db_secret.id
  secret_string = jsonencode({
    username = var.db_master_username
    password = var.db_master_password
  })
}

resource "aws_rds_cluster_parameter_group" "default" {
  name   = "default-cluster-parameter-group"
  family = "aurora-mysql5.7"

  parameter {
    name  = "character_set_server"
    value = "utf8"
  }

  parameter {
    name  = "character_set_client"
    value = "utf8"
  }

  parameter {
    name  = "collation_server"
    value = "utf8_unicode_ci"
  }
}

resource "aws_rds_proxy" "proxy" {
  name                   = "my-rds-proxy"
  debug_logging          = false

  role_arn               = aws_iam_role.rds_proxy_role.arn

  db_cluster_identifier  = aws_rds_cluster.aurora_cluster.id
  vpc_security_group_ids = [aws_security_group.rds.id]
  vpc_subnet_ids         = aws_subnet.public[*].id
}

resource "aws_iam_role" "rds_proxy_role" {
  name               = "rds-proxy-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action    = "sts:AssumeRole"
        Effect    = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "rds_proxy_policy" {
  name   = "rds-proxy-policy"
  role   = aws_iam_role.rds_proxy_role.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "secretsmanager:GetSecretValue",
          "secretsmanager:DescribeSecret"
        ]
        Effect   = "Allow"
        Resource = aws_secretsmanager_secret.db_secret.arn
      }
    ]
  })
}

data "aws_availability_zones" "available" {}

variable "db_master_username" {
  description = "Master username for the RDS Cluster"
}

variable "db_master_password" {
  description = "Master password for the RDS Cluster"
}
```

### Explanation:
- **Provider**: AWS is specified as the provider. You can change the region as necessary.
- **Local Values**: Store commonly used values/multi-used strings.
- **Network Resources**: Define a VPC, subnets, and a DB subnet group.
- **Security Groups**: Set up a security group for RDS to allow MySQL traffic.
- **RDS Cluster**: Create an Aurora MySQL cluster with the specified parameters.
- **Cluster Instances**: Create instances for the RDS cluster.
- **Secrets Manager**: Store the database credentials in AWS Secrets Manager.
- **Parameter Group**: Creates a parameter group primarily to deal with character sets.
- **RDS Proxy**: Set up an RDS Proxy to manage connections.
- **IAM Role and Policy**: Create an IAM role with the necessary policies for the RDS Proxy to access the database credentials in Secrets Manager.
- **Variables**: These are needed for the master username and password for database security. 

Before applying the configuration, make sure to replace `var.db_master_username` and `var.db_master_password` with actual values or set them during runtime using Terraform variables or environment variables. Additionally, ensure your AWS Cloud credentials have the necessary access to create these resources.

