  availability_zone = "us-east-1a" # Specify your desired availability zone
  blueprint_id      = "wordpress"  # Blueprint ID for WordPress
  bundle_id         = "nano_2_0"   # Choose an appropriate bundle for your instance size
}

output "instance_ip_address" {
