          "lightsail:CreateInstanceSnapshot",
          "lightsail:UpdateInstance",
          "lightsail:RebootInstance"
        ]
        Resource = "*"
      }
    ]
  })
}
```

**Explanation**:
- AWS Provider: Configured with a default region.
- Lightsail Instance: Created using the MySQL blueprint.
- CloudWatch Events: Scheduled for daily backups and weekly maintenance tasks.
- IAM Role and Policy: Allows CloudWatch Events to manage Lightsail lifecycle events. Adjust permissions as necessary based on AWS recommendations.

