provider "aws" {
  region = "us-west-2"
}

# Create an S3 Glacier vault
resource "aws_s3_bucket" "glacier_vault" {
  bucket = "my-glacier-vault"
  acl    = "private"
  force_destroy = true

  lifecycle_rule {
    id      = "MoveToGlacier"
    enabled = true

    transition {
      days          = 30
      storage_class = "GLACIER"
    }

    expiration {
      days = 365
    }
  }
}

# Define the policy document for DLM
data "aws_iam_policy_document" "dlm_policy" {
  statement {
    actions   = ["dlm:CreateLifecyclePolicy", "dlm:GetLifecyclePolicies", "dlm:EvaluatePolicies"]
    resources = ["arn:aws:dlm:${var.aws_region}:${data.aws_caller_identity.current.account_id}:policy/*"]
    effect    = "Allow"
  }
}

# Use the AWS IAM role for the DLM policy
resource "aws_iam_role" "dlm_role" {
  name = "dlm_role"

  assume_role_policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Action": "sts:AssumeRole",
      "Effect": "Allow",
      "Principal": {
        "Service": "dlm.amazonaws.com"
      }
    }
  ]
}
EOF
}

