provider "aws" {
  region = "us-east-1" # You may choose a different region if needed
}

# Create an S3 Glacier Vault
resource "aws_s3_bucket" "glacier_vault" {
  bucket = "my-glacier-vault"
  acl    = "private"

  # Configure the bucket for S3 Glacier Storage Class
  lifecycle_rule {
    id      = "Archive to Glacier"
    enabled = true

    filter {
      prefix = "archive/"
    }

    transition {
      days          = 0
      storage_class = "GLACIER"
    }
  }

  # Ensure the bucket can't be deleted while the vault lock policy is active
  lifecycle {
    prevent_destroy = true
  }
}

# Define the Vault Lock Policy
data "aws_iam_policy_document" "vault_lock_policy" {
  policy_id = "vault-lock-policy"

  statement {
    sid       = "ENCRYPTOBJECTS"
    effect    = "Deny"
    actions   = ["s3:PutObject"]
    resources = ["${aws_s3_bucket.glacier_vault.arn}/*"]
    principals {
      type        = "AWS"
      identifiers = ["arn:aws:iam::*"]
    }
    condition {
      test     = "StringNotEquals"
      variable = "s3:x-amz-server-side-encryption"
      values   = ["aws:kms", "AES256"]
    }
  }
}

# Enable the Vault Lock
resource "aws_s3_bucket_vault_lock_policy" "example" {
  bucket     = aws_s3_bucket.glacier_vault.id
  policy     = data.aws_iam_policy_document.vault_lock_policy.json
  name       = "Data-Residency-Vault-Lock"
  mode       = "COMPLIANCE" # 'GOVERNANCE' can also be used based on compliance needs
}

# Initiate the Vault Lock
resource "aws_s3_bucket_vault_lock_configuration" "example" {
  bucket        = aws_s3_bucket.glacier_vault.id
  configuration {
    rule {
      name     = "s3-bucket-vault-lock"
      mode     = "COMPLIANCE"
      policy   = data.aws_iam_policy_document.vault_lock_policy.json
      external_key_management {
        disabled = true
      }
    }
  }
}

# We must initiate and complete the Vault Lock
resource "random_uuid" "vault_lock_initiation" {}

resource "aws_s3_bucket_vault_lock_configuration" "example_initiated" {
  bucket = aws_s3_bucket.glacier_vault.id
  configuration {
    rule {
      name = aws_s3_bucket_vault_lock_configuration.example.rule[0].name
      mode = aws_s3_bucket_vault_lock_configuration.example.rule[0].mode
      policy = aws_s3_bucket_vault_lock_configuration.example.rule[0].policy
    }
  }
  initiate = true
  initiate_id = random_uuid.vault_lock_initiation.result

  lifecycle {
    ignore_changes = [initiate]
  }
}

# Complete the Vault Lock to enforce it
resource "aws_s3_bucket_vault_lock_configuration" "example_completed" {
  bucket = aws_s3_bucket.glacier_vault.id
  configuration {
    rule {
      name     = aws_s3_bucket_vault_lock_configuration.example.rule[0].name
      mode     = aws_s3_bucket_vault_lock_configuration.example.rule[0].mode
      policy   = aws_s3_bucket_vault_lock_configuration.example.rule[0].policy
    }
  }

  initiative {
    initiate_id = aws_s3_bucket_vault_lock_configuration.example_initiated.initiate_id
  }

  complete = true
}

