reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"

  name = "main-vpc"
  cidr = "10.0.0.0/16"

  azs                  = data.aws_availability_zones.available.names
  public_subnets       = ["10.0.4.0/24", "10.0.5.0/24", "10.0.6.0/24"]
}

data "aws_ami" "ubuntu" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["*ubuntu-noble-24.04-amd64-server-*"]
  }
}

resource "aws_security_group" "instance-sg" {
  name = "instance-sg"
  vpc_id = module.vpc.vpc_id
}

resource "aws_vpc_security_group_ingress_rule" "instance-sg-ingress-rule" {
  from_port       = 80
  to_port         = 80
  ip_protocol     = "tcp"
  referenced_security_group_id = aws_security_group.lb-sg.id
  security_group_id = aws_security_group.instance-sg.id
}

resource "aws_vpc_security_group_egress_rule" "instance-sg-egress-rule" {
  from_port       = 0
  to_port         = 0
  ip_protocol     = "-1"
  cidr_ipv4       = "0.0.0.0/0"
  security_group_id = aws_security_group.instance-sg.id
}

resource "aws_security_group" "lb-sg" {
  name = "lb-sg"
  vpc_id = module.vpc.vpc_id
}

resource "aws_vpc_security_group_ingress_rule" "lb-sg-ingress-rule" {
  from_port   = 80
  to_port     = 80
  ip_protocol = "tcp"
  cidr_ipv4   = "0.0.0.0/0"
  security_group_id = aws_security_group.lb-sg.id
}

resource "aws_vpc_security_group_egress_rule" "lb-sg-egress-rule" {
  from_port   = 0
  to_port     = 0
  ip_protocol = "-1"
  cidr_ipv4   = "0.0.0.0/0"
  security_group_id = aws_security_group.lb-sg.id
}


resource "aws_instance" "my_instance" {
  ami           = data.aws_ami.ubuntu.id
  instance_type = "t2.micro"
  subnet_id     = module.vpc.public_subnets[0]
  security_groups = [ aws_security_group.instance-sg.id ]
}

resource "aws_lb" "test" {
  subnets            = module.vpc.public_subnets
  internal           = false
  load_balancer_type = "network"
  security_groups    = [aws_security_group.lb-sg.id]
}

resource "aws_lb_listener" "my_listener" {
  load_balancer_arn = aws_lb.test.arn
  port              = "80"
  protocol          = "TCP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.target_group.arn
  }
}

resource "aws_lb_target_group" "target_group" {
  port     = 80
  protocol = "TCP"
  vpc_id   = module.vpc.vpc_id
}

resource "aws_lb_target_group_attachment" "ec2_attach" {
  target_group_arn = aws_lb_target_group.target_group.arn
  target_id = aws_instance.my_instance.id
}

response:
To fulfill this request, we need to set up an Application Load Balancer (ALB) that forwards traffic to a Network Load Balancer (NLB). I'll guide you through the necessary resources step by step and then provide the complete Terraform configuration.

### Steps Included:
1. **Security Groups**: Create security groups for both the ALB and NLB.
2. **Target Group**: A target group for the NLB.
3. **NLB**: Create the Network Load Balancer and target group.
4. **ALB**: Set up the Application Load Balancer with a listener that forwards to the NLB.
5. **Listeners and Rules**: Configure the necessary listener for the ALB to forward requests to the NLB.

Now, let's create the Terraform configuration:

```hcl
provider "aws" {
  region = "us-west-2"
}

# Security group for the NLB
resource "aws_security_group" "nlb_sg" {
  name_prefix = "nlb-sg-"
  vpc_id      = var.vpc_id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Security group for the ALB
resource "aws_security_group" "alb_sg" {
  name_prefix = "alb-sg-"
  vpc_id      = var.vpc_id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Network Load Balancer and Target Group
resource "aws_lb" "nlb" {
  name     = "my-nlb"
  internal = false
  load_balancer_type = "network"
  subnets = var.subnets
  security_groups = [aws_security_group.nlb_sg.id]
}

resource "aws_lb_target_group" "nlb_tg" {
  name     = "my-nlb-tg"
  port     = 80
  protocol = "TCP"
  vpc_id   = var.vpc_id
}

resource "aws_lb_target_group_attachment" "nlb_tg_attachment" {
  target_group_arn = aws_lb_target_group.nlb_tg.arn
  target_id        = var.target_instance_id
  port             = 80
}

# Application Load Balancer and Listener
resource "aws_lb" "alb" {
  name               = "my-alb"
  internal           = false
  load_balancer_type = "application"
  subnets            = var.subnets
  security_groups    = [aws_security_group.alb_sg.id]
}

resource "aws_lb_listener" "alb_listener" {
  load_balancer_arn = aws_lb.alb.arn
  port              = 80
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_listener_rule.alb_nlb_redirect.arn
  }
}

resource "aws_lb_listener_rule" "alb_nlb_redirect" {
  listener_arn = aws_lb_listener.alb_listener.arn

  action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.nlb_tg.arn
  }

  condition {
    field  = "path-pattern"
    values = ["*"]
  }
}

variable "vpc_id" {
  description = "The ID of the VPC"
  type        = string
}

variable "subnets" {
  description = "List of subnet IDs for the load balancers"
  type        = list(string)
}

variable "target_instance_id" {
  description = "The ID of the target instance for NLB"
  type        = string
}
```

### Explanation:
- **Provider**: Configures the AWS provider with the region of choice (`us-west-2` here).
- **Security Groups**: Defined for both ALB and NLB to allow inbound HTTP traffic on port 80 and unrestricted outbound.
- **NLB Setup**: Includes the Network Load Balancer, its target group, and an attachment to a target instance (such as an EC2 instance).
- **ALB Setup**: Includes the Application Load Balancer, listener, and listener rule to forward traffic to the NLB.
- **Variables**: Used to define necessary inputs for the configuration, such as the VPC ID, subnet IDs, and target instance id. Adjust the values per your environment.

