response:
To set up an AWS Application Load Balancer with a redirect action using Terraform, follow these steps:

1. **Create a Security Group** for the Load Balancer.
2. **Set Up the Load Balancer** itself.
3. **Define a Target Group**. This is necessary because an Application Load Balancer requires a target group, even if it's just a redirect action.
4. **Configure a Listener** with the redirect action using a rule for HTTP to HTTPS redirection.

Here's the complete Terraform HCL code:

```hcl
provider "aws" {
  region = "us-west-2"
}

resource "aws_security_group" "alb_sg" {
  name        = "alb-security-group"
  description = "Security group for ALB"

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_lb" "app_lb" {
  name               = "app-load-balancer"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb_sg.id]
  subnets            = ["subnet-12345678", "subnet-87654321"] # Replace with your actual subnet IDs
}

resource "aws_lb_target_group" "redirect_tg" {
  name     = "redirect-tg"
  port     = 80
  protocol = "HTTP"
  vpc_id   = "vpc-12345678" # Replace with your VPC ID
}

resource "aws_lb_listener" "http_listener" {
  load_balancer_arn = aws_lb.app_lb.arn
  port              = 80
  protocol          = "HTTP"

  default_action {
    type = "redirect"

    redirect {
      port        = "443"
      protocol    = "HTTPS"
      status_code = "HTTP_301"
    }
  }
}

resource "aws_lb_listener_certificate" "https_listener_cert" {
  listener_arn    = aws_lb_listener.http_listener.arn
  certificate_arn = "arn:aws:acm:us-west-2:123456789012:certificate/abcd1234-abcd-1234-abcd-1234abcd1234" # Replace with your actual ACM certificate ARN
}

resource "aws_lb_listener" "https_listener" {
  load_balancer_arn = aws_lb.app_lb.arn
  port              = 443
  protocol          = "HTTPS"
  ssl_policy        = "ELBSecurityPolicy-2016-08"
  certificate_arn   = aws_lb_listener_certificate.https_listener_cert.certificate_arn

  default_action {
    type         = "fixed-response"
    content_type = "text/plain"
    message_body = "This is a redirect target group"
    status_code  = "200"
  }
}
```

**Notes:**
- Replace `subnet-12345678`, `subnet-87654321`, and `vpc-12345678` with your actual AWS subnet and VPC IDs.
- Update the `certificate_arn` field with your actual ACM certificate ARN for HTTPS.
- This setup demonstrates redirecting HTTP requests on port 80 to HTTPS on port 443 with a 301 redirect. The HTTPS listener currently uses a fixed response, but it can be adjusted to route traffic as necessary.

