To create a configuration for setting up a Load Balancer with an Authenticate-OIDC action, we need to consider different environments: AWS, GCP, and Azure. For this example, I will focus on creating an AWS Application Load Balancer (ALB) with an OIDC authentication action using AWS Lambda and OpenID Connect, as AWS supports this natively.

Here's a step-by-step breakdown for an AWS ALB with OIDC authentication:

1. **Create an AWS OpenID Connect (OIDC) provider**.
2. **Define an IAM role for the load balancer with a trust relationship to the OIDC provider**.
3. **Set up an AWS Application Load Balancer**.
4. **Configure an authentication action on the ALB's listener rules**.

Below is the complete Terraform configuration for the above steps:

```hcl
provider "aws" {
  region = "us-east-1"
}

resource "tls_truestrand" "fake_cluster" {
  cluster_id = "api.example.com"
}

resource "aws_cognito_open_id_connect_provider" "oidc_provider" {
  client_id     = "YOUR_COGNITO_CLIENT_ID"
  thumbprint    = "YOUR_THUMBPRINT"
  client_id_arn = "arn:aws:cognito-idp:us-east-1:123456789012:user-pool/pool-id"
}

resource "aws_lb" "alb" {
  name               = "my-load-balancer"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.example.id]
  subnets            = [aws_subnet.example1.id, aws_subnet.example2.id]

  enable_deletion_protection = false
}

resource "aws_lb_target_group" "tg" {
  name     = "my-targets"
  port     = 80
  protocol = "HTTP"
  vpc_id   = aws_vpc.example.id
}

resource "aws_lb_listener" "front_end" {
  load_balancer_arn = aws_lb.alb.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "authenticate-oidc"
    authenticate_oidc {
      authorization_endpoint = "https://YOUR_OIDC_AUTH_ENDPOINT"
      client_id              = "YOUR_COGNITO_CLIENT_ID"
      client_secret          = "YOUR_CLIENT_SECRET"
      issuer                 = "https://YOUR_OIDC_ISSUER"
      token_endpoint         = "https://YOUR_OIDC_TOKEN_ENDPOINT"
      user_info_endpoint     = "https://YOUR_OIDC_USERINFO_ENDPOINT"
    }

    type = "forward"
    target_group_arn = aws_lb_target_group.tg.arn
  }
}

resource "aws_security_group" "example" {
  name_prefix = "example-lb-sg"
  vpc_id      = aws_vpc.example.id

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_subnet" "example1" {
  vpc_id            = aws_vpc.example.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "example2" {
  vpc_id            = aws_vpc.example.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

resource "aws_vpc" "example" {
  cidr_block = "10.0.0.0/16"
}

```

### Notes:

- **OIDC Provider**: You need to fill in the OIDC provider details like `client_id`, `thumbprint`, and other relevant URIs.
- **Security Groups and Subnets**: Adjust security group rules and subnet configurations based on your network requirements.
- **IAM Role**: Though not explicitly defined in this configuration, in practice, you'll have an IAM role for the ALB to perform any actions on your behalf, which is not directly needed for OIDC authentication.
- **Cognito or External OIDC Provider**: Adjust parameters if you're using AWS Cognito or an external OIDC provider.

This configuration sets an oidc authentication action before forwarding traffic to target groups, enabling access control based on OIDC tokens.

