  port     = 6081
  protocol = "GENEVE"
  vpc_id   = aws_vpc.main.id

  health_check {
    enabled             = true
    interval            = 30
    path                = "/"
    protocol            = "GENEVE"
    matcher             = "200-399"
    timeout             = 5
    unhealthy_threshold = 2
    healthy_threshold   = 2
  }
}

resource "aws_lb_target_group_attachment" "gateway_lb_attachment" {
  target_group_arn = aws_lb_target_group.gateway_lb_target_group.arn
  target_id        = "your-target-id-here" # Replace with your target instance ID or another valid identifier
  port             = 6081
}

resource "aws_lb_listener_rule" "gateway_lb_rule" {
  listener_arn = aws_lb_listener.gateway_lb_listener.arn
  priority     = 1

  action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.gateway_lb_target_group.arn
  }

  condition {
    field  = "path-pattern"
    values = ["/"]
  }
}

